import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  server: {
    port: 3000,
    open: true
  }
});

import { createClient } from "@supabase/supabase-js";

const url = import.meta.env.VITE_SUPABASE_URL ?? "";
const anonKey = import.meta.env.VITE_SUPABASE_ANON_KEY ?? "";

export const supabaseConfigured = Boolean(url && anonKey);

export const supabase = createClient(url, anonKey, {
  auth: {
    persistSession: true,
    autoRefreshToken: true
  }
});

let deterministicSeed = 1_234_567_89;

export function resetDeterministicSeed() {
  deterministicSeed = 1_234_567_89;
}

export function seededRandom() {
  deterministicSeed = (1_664_525 * deterministicSeed + 1_013_904_223) % 4_294_967_296;
  return deterministicSeed / 4_294_967_296;
}

export function randomItemSeeded(arr) {
  return arr[Math.floor(seededRandom() * arr.length)];
}

export function randomTargetItem(arr) {
  const cryptoObj = globalThis.crypto;
  if (cryptoObj?.getRandomValues) {
    const values = new Uint32Array(1);
    cryptoObj.getRandomValues(values);
    return arr[values[0] % arr.length];
  }
  return arr[Math.floor(Math.random() * arr.length)];
}

export function calculateAgeFromBirthDate(birthDateValue) {
  if (!birthDateValue) return null;
  const birthDate = new Date(`${birthDateValue}T00:00:00`);
  if (Number.isNaN(birthDate.getTime())) return null;

  const today = new Date();
  let age = today.getFullYear() - birthDate.getFullYear();
  const monthDifference = today.getMonth() - birthDate.getMonth();
  if (monthDifference < 0 || (monthDifference === 0 && today.getDate() < birthDate.getDate())) {
    age -= 1;
  }
  return age;
}

export function getProfileKeyByAge(age) {
  const n = Number(age);
  if (!Number.isFinite(n)) return "adult";
  if (n >= 6 && n <= 12) return "child";
  if (n >= 13 && n <= 17) return "teen";
  return "adult";
}

function clamp(value, min = 0, max = 100) {
  return Math.max(min, Math.min(max, value));
}

function safeDivide(a, b) {
  if (!b || b === 0) return 0;
  return a / b;
}

function mean(arr) {
  if (!arr.length) return 0;
  return arr.reduce((sum, v) => sum + v, 0) / arr.length;
}

function median(arr) {
  if (!arr.length) return 0;
  const sorted = [...arr].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

function standardDeviation(arr) {
  if (arr.length < 2) return 0;
  const avg = mean(arr);
  return Math.sqrt(mean(arr.map((v) => (v - avg) ** 2)));
}

function inverseNormalCDF(p) {
  if (p <= 0 || p >= 1) return 0;

  const a1 = -39.6968302866538;
  const a2 = 220.946098424521;
  const a3 = -275.928510446969;
  const a4 = 138.357751867269;
  const a5 = -30.6647980661472;
  const a6 = 2.50662827745924;
  const b1 = -54.4760987982241;
  const b2 = 161.585836858041;
  const b3 = -155.698979859887;
  const b4 = 66.8013118877197;
  const b5 = -13.2806815528857;
  const c1 = -0.00778489400243029;
  const c2 = -0.322396458041136;
  const c3 = -2.40075827716184;
  const c4 = -2.54973253934373;
  const c5 = 4.37466414146497;
  const c6 = 2.93816398269878;
  const d1 = 0.00778469570904146;
  const d2 = 0.32246712907004;
  const d3 = 2.445134137143;
  const d4 = 3.75440866190742;
  const pLow = 0.02425;
  const pHigh = 1 - pLow;

  let q;
  let r;

  if (p < pLow) {
    q = Math.sqrt(-2 * Math.log(p));
    return (((((c1 * q + c2) * q + c3) * q + c4) * q + c5) * q + c6) / ((((d1 * q + d2) * q + d3) * q + d4) * q + 1);
  }

  if (p <= pHigh) {
    q = p - 0.5;
    r = q * q;
    return (((((a1 * r + a2) * r + a3) * r + a4) * r + a5) * r + a6) * q / (((((b1 * r + b2) * r + b3) * r + b4) * r + b5) * r + 1);
  }

  q = Math.sqrt(-2 * Math.log(1 - p));
  return -(((((c1 * q + c2) * q + c3) * q + c4) * q + c5) * q + c6) / ((((d1 * q + d2) * q + d3) * q + d4) * q + 1);
}

function correctedRate(rate, total) {
  if (!total || total <= 0) return 0.5;
  if (rate <= 0) return 0.5 / total;
  if (rate >= 1) return 1 - 0.5 / total;
  return rate;
}

export function getTrialOutcome(trial, lateResponseMs) {
  if (trial.responseCount > 1) return "multiPress";
  if (trial.isTarget && !trial.responded) return "omission";
  if (!trial.isTarget && trial.responded) return "impulsive";
  if (trial.isTarget && trial.responded && trial.reactionTime > lateResponseMs) return "late";
  if (trial.isTarget && trial.responded) return "correct";
  return "correctReject";
}

export function calculateAdvancedMetrics(logs, lateResponseMs) {
  const targets = logs.filter((t) => t.isTarget);
  const nonTargets = logs.filter((t) => !t.isTarget);
  const correctHits = targets.filter((t) => t.responded && t.reactionTime <= lateResponseMs);
  const allTargetResponses = targets.filter((t) => t.responded);
  const omissions = targets.filter((t) => !t.responded);
  const lateResponses = targets.filter((t) => t.responded && t.reactionTime > lateResponseMs);
  const impulsiveErrors = nonTargets.filter((t) => t.responded);
  const correctRejects = nonTargets.filter((t) => !t.responded);
  const multiPress = logs.filter((t) => t.responseCount > 1);
  const validReactionTimes = allTargetResponses.map((t) => t.reactionTime).filter((rt) => typeof rt === "number" && rt > 0);

  const hitRate = safeDivide(correctHits.length, targets.length);
  const targetResponseRate = safeDivide(allTargetResponses.length, targets.length);
  const omissionRate = safeDivide(omissions.length, targets.length);
  const falseAlarmRate = safeDivide(impulsiveErrors.length, nonTargets.length);
  const lateRate = safeDivide(lateResponses.length, targets.length);
  const multiPressRate = safeDivide(multiPress.length, logs.length);
  const accuracy = safeDivide(correctHits.length + correctRejects.length, logs.length) * 100;
  const dPrime =
    inverseNormalCDF(correctedRate(targetResponseRate, targets.length)) -
    inverseNormalCDF(correctedRate(falseAlarmRate, nonTargets.length));
  const rtMean = mean(validReactionTimes);
  const rtMedian = median(validReactionTimes);
  const rtStd = standardDeviation(validReactionTimes);

  const attentionScore = clamp(100 - omissionRate * 55 - lateRate * 25 - falseAlarmRate * 20);
  const impulseControlScore = clamp(100 - falseAlarmRate * 70 - multiPressRate * 30);
  const processingSpeedScore = clamp(100 - Math.max(0, rtMedian - 450) * 0.08 - lateRate * 30);
  const consistencyScore = clamp(100 - Math.max(0, rtStd - 120) * 0.18 - lateRate * 15);
  const overallScore = clamp(
    attentionScore * 0.35 + impulseControlScore * 0.25 + processingSpeedScore * 0.2 + consistencyScore * 0.2
  );

  const flags = [];
  if (omissionRate >= 0.25) flags.push("Sürdürülebilir dikkat alanında belirgin zorlanma");
  if (falseAlarmRate >= 0.2) flags.push("Dürtü kontrolü / yanıt inhibisyonunda zorlanma");
  if (lateRate >= 0.2) flags.push("Geç tepki ve işlem hızı alanında zorlanma");
  if (multiPressRate >= 0.1) flags.push("Tekrarlı basma / motor kontrol düzensizliği");
  if (rtStd >= 220) flags.push("Tepki süresinde yüksek dalgalanma");

  return {
    totalTrials: logs.length,
    targets: targets.length,
    nonTargets: nonTargets.length,
    correctHits: correctHits.length,
    targetResponses: allTargetResponses.length,
    correctRejects: correctRejects.length,
    omissions: omissions.length,
    lateResponses: lateResponses.length,
    impulsiveErrors: impulsiveErrors.length,
    multiPress: multiPress.length,
    avgReaction: Math.round(rtMean),
    medianReaction: Math.round(rtMedian),
    rtStd: Math.round(rtStd),
    accuracy: Math.round(accuracy),
    hitRate: hitRate * 100,
    omissionRate: omissionRate * 100,
    falseAlarmRate: falseAlarmRate * 100,
    lateRate: lateRate * 100,
    multiPressRate: multiPressRate * 100,
    dPrime,
    attentionScore,
    impulseControlScore,
    processingSpeedScore,
    consistencyScore,
    overallScore,
    flags
  };
}

export function getPhaseComment(sectionName, score) {
  if (score >= 75) return "Performans bu fazda genel olarak korunmuştur.";
  if (sectionName.includes("Hız")) return "Hız baskısı altında performansta düşüş izlenmiştir.";
  if (sectionName.includes("Görsel") && sectionName.includes("İşitsel")) {
    return "Çoklu duyusal yük altında dikkat ve dürtü kontrolü zorlanmıştır.";
  }
  if (sectionName.includes("Görsel")) return "Görsel çeldiriciler altında dikkat performansı zayıflamıştır.";
  if (sectionName.includes("İşitsel")) return "İşitsel çeldiriciler altında performans etkilenmiştir.";
  if (sectionName.includes("Kapanış")) return "Testin son bölümünde yorgunluk etkisi görülebilir.";
  return "Bu fazda performansta düşüş izlenmiştir.";
}

export function getRiskLevel(metrics) {
  if (metrics.overallScore < 60 || metrics.omissionRate >= 25 || metrics.falseAlarmRate >= 20 || metrics.rtStd >= 250) {
    return "Yüksek";
  }
  if (
    metrics.overallScore < 75 ||
    metrics.lateRate >= 20 ||
    metrics.multiPressRate >= 10 ||
    metrics.flags.length >= 2
  ) {
    return "Orta";
  }
  return "Düşük";
}

export function formatDurationSeconds(ms) {
  return Math.round(ms / 1000);
}

export function getGifPosition(area, zone, fileName) {
  const rowMap = { upper: 26, middle: 50, lower: 74 };
  let left = area === "left" ? 18 : 82;
  let top = rowMap[zone] || 50;

  if (area === "right" && (fileName === "Araba" || fileName === "Araba Korna")) {
    left = 83;
    top = Math.max(26, top - 2);
  }

  return { left, top };
}

export function getShapeSvg(shape, color) {
  if (shape === "circle") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><circle cx="40" cy="40" r="35" fill="${color}"/></svg>`;
  }
  if (shape === "square") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><rect x="12" y="12" width="56" height="56" fill="${color}"/></svg>`;
  }
  if (shape === "triangle") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><polygon points="40,8 8,72 72,72" fill="${color}"/></svg>`;
  }
  if (shape === "diamond") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><polygon points="40,6 74,40 40,74 6,40" fill="${color}"/></svg>`;
  }
  if (shape === "pentagon") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><polygon points="40,6 74,32 61,72 19,72 6,32" fill="${color}"/></svg>`;
  }
  if (shape === "hexagon") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><polygon points="22,8 58,8 74,40 58,72 22,72 6,40" fill="${color}"/></svg>`;
  }
  if (shape === "vertical") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><rect x="28" y="6" width="24" height="68" fill="${color}"/></svg>`;
  }
  if (shape === "horizontal") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><rect x="6" y="28" width="68" height="24" fill="${color}"/></svg>`;
  }
  if (shape === "plus") {
    return `<svg width="80" height="80" viewBox="0 0 80 80"><rect x="32" y="8" width="16" height="64" fill="${color}"/><rect x="8" y="32" width="64" height="16" fill="${color}"/></svg>`;
  }
  return `<svg width="80" height="80" viewBox="0 0 80 80"><line x1="15" y1="15" x2="65" y2="65" stroke="${color}" stroke-width="14" stroke-linecap="round"/><line x1="65" y1="15" x2="15" y2="65" stroke="${color}" stroke-width="14" stroke-linecap="round"/></svg>`;
}

export function ShapeView({ shape, color, size = 120 }) {
  const base = { width: size, height: size, background: color, display: "inline-block" };

  if (shape === "circle") return <div style={{ ...base, borderRadius: "50%" }} />;
  if (shape === "square") return <div style={base} />;
  if (shape === "triangle") {
    return <div style={{ ...base, clipPath: "polygon(50% 0%, 0% 100%, 100% 100%)" }} />;
  }
  if (shape === "diamond") return <div style={{ ...base, transform: "rotate(45deg)" }} />;
  if (shape === "pentagon") {
    return <div style={{ ...base, clipPath: "polygon(50% 0%, 100% 38%, 82% 100%, 18% 100%, 0% 38%)" }} />;
  }
  if (shape === "hexagon") {
    return <div style={{ ...base, clipPath: "polygon(25% 0%, 75% 0%, 100% 50%, 75% 100%, 25% 100%, 0% 50%)" }} />;
  }
  if (shape === "vertical") {
    return <div style={{ width: size * 0.45, height: size, background: color, display: "inline-block" }} />;
  }
  if (shape === "horizontal") {
    return <div style={{ width: size, height: size * 0.45, background: color, display: "inline-block" }} />;
  }
  if (shape === "plus") {
    return (
      <div style={{ width: size, height: size, position: "relative", display: "inline-block" }}>
        <div
          style={{
            position: "absolute",
            left: size * 0.4,
            top: 0,
            width: size * 0.2,
            height: size,
            background: color
          }}
        />
        <div
          style={{
            position: "absolute",
            left: 0,
            top: size * 0.4,
            width: size,
            height: size * 0.2,
            background: color
          }}
        />
      </div>
    );
  }
  if (shape === "xshape") {
    return (
      <div style={{ width: size, height: size, position: "relative", display: "inline-block" }}>
        <div
          style={{
            position: "absolute",
            left: size * 0.43,
            top: 0,
            width: size * 0.14,
            height: size,
            background: color,
            transform: "rotate(45deg)"
          }}
        />
        <div
          style={{
            position: "absolute",
            left: size * 0.43,
            top: 0,
            width: size * 0.14,
            height: size,
            background: color,
            transform: "rotate(-45deg)"
          }}
        />
      </div>
    );
  }
  return null;
}

import { useCallback, useEffect, useRef, useState } from "react";
import { COLORS, GIF_FILES, INDEPENDENT_SOUNDS, SHAPES } from "./constants.js";
import { getGifPosition } from "./shapeUtils.js";
import { randomTargetItem, randomItemSeeded, resetDeterministicSeed, seededRandom } from "../../domain/random.js";

export function useAttentionTest(activeProfile) {
  const [target, setTarget] = useState(null);
  const [scene, setScene] = useState(null);
  const [gifDistractors, setGifDistractors] = useState([]);
  const [sessionStage, setSessionStage] = useState("idle");

  const targetRef = useRef(null);
  const trialLog = useRef([]);
  const currentTrial = useRef(null);
  const timer = useRef(null);
  const testClockTimer = useRef(null);
  const eventTimers = useRef([]);
  const lastInputTime = useRef(0);
  const audioRefs = useRef({});
  const isPlayingRef = useRef(false);
  const testStartTimeRef = useRef(0);
  const activeGifIdsRef = useRef([]);
  const activeSoundGifIdsRef = useRef([]);
  const independentSoundIdRef = useRef(null);

  const createNewTarget = useCallback(() => {
    const previousTarget = targetRef.current;
    let newTarget;
    let guard = 0;
    do {
      newTarget = { shape: randomTargetItem(SHAPES), color: randomTargetItem(COLORS) };
      guard += 1;
    } while (
      previousTarget &&
      newTarget.shape === previousTarget.shape &&
      newTarget.color === previousTarget.color &&
      guard < 50
    );
    targetRef.current = newTarget;
    setTarget(newTarget);
  }, []);

  const getElapsedMs = useCallback(() => {
    if (!testStartTimeRef.current) return 0;
    return performance.now() - testStartTimeRef.current;
  }, []);

  const getPhaseInfo = useCallback(
    (elapsedMs = getElapsedMs()) => {
      return (
        activeProfile.phases.find((phase) => elapsedMs < phase.end) ||
        activeProfile.phases[activeProfile.phases.length - 1]
      );
    },
    [activeProfile.phases]
  );

  const clearEventTimers = useCallback(() => {
    eventTimers.current.forEach((id) => clearTimeout(id));
    eventTimers.current = [];
  }, []);

  const stopAllAudio = useCallback(() => {
    Object.values(audioRefs.current).forEach((audio) => {
      if (audio) {
        audio.pause();
        audio.currentTime = 0;
        audio.loop = false;
        audio.src = "";
      }
    });
    audioRefs.current = {};
    independentSoundIdRef.current = null;
    activeSoundGifIdsRef.current = [];
  }, []);

  const stopAllSystems = useCallback(() => {
    clearEventTimers();
    stopAllAudio();
    activeGifIdsRef.current = [];
    activeSoundGifIdsRef.current = [];
    setGifDistractors([]);
  }, [clearEventTimers, stopAllAudio]);

  const removeGifItem = useCallback(
    (id) => {
      const audio = audioRefs.current[id];
      if (audio) {
        audio.pause();
        audio.currentTime = 0;
        audio.loop = false;
        audio.src = "";
        delete audioRefs.current[id];
      }
      activeGifIdsRef.current = activeGifIdsRef.current.filter((itemId) => itemId !== id);
      activeSoundGifIdsRef.current = activeSoundGifIdsRef.current.filter((itemId) => itemId !== id);
      setGifDistractors((prev) => prev.filter((item) => item.id !== id));
    },
    []
  );

  const canAddGifItems = useCallback((items) => {
    const activeGifCount = activeGifIdsRef.current.length;
    const activeSoundGifCount = activeSoundGifIdsRef.current.length;
    const incomingCount = items.length;
    const incomingSoundCount = items.filter((item) => !item.silent).length;
    if (incomingCount === 0) return false;
    if (activeGifCount + incomingCount > 2) return false;
    if (activeSoundGifCount + incomingSoundCount > 1) return false;
    if (incomingSoundCount > 1) return false;
    return true;
  }, []);

  const showFixedGifEvent = useCallback(
    (eventIndex) => {
      const event = activeProfile.gifEvents[eventIndex];
      if (!event || !isPlayingRef.current) return;
      if (!canAddGifItems(event.items)) return;

      const items = event.items.map((raw, index) => {
        const file = GIF_FILES[raw.key];
        if (!file) return null;
        const position = getGifPosition(raw.area, raw.zone, file.name);
        const id = `gif-${eventIndex}-${index}-${Date.now()}`;
        return {
          id,
          name: file.name,
          gif: file.gif,
          sound: raw.silent ? null : file.sound,
          left: position.left,
          top: position.top,
          area: raw.area,
          zone: raw.zone,
          size: file.size
        };
      }).filter(Boolean);

      if (!items.length) return;

      activeGifIdsRef.current = [...activeGifIdsRef.current, ...items.map((item) => item.id)];
      activeSoundGifIdsRef.current = [
        ...activeSoundGifIdsRef.current,
        ...items.filter((item) => item.sound).map((item) => item.id)
      ];

      setGifDistractors((prev) => [...prev, ...items]);

      items.forEach((item) => {
        if (item.sound) {
          const audio = new Audio(item.sound);
          audio.loop = true;
          audio.volume = 0.7;
          audioRefs.current[item.id] = audio;
          audio.play().catch(() => removeGifItem(item.id));
        }
        const removeTimer = setTimeout(() => removeGifItem(item.id), event.duration);
        eventTimers.current.push(removeTimer);
      });
    },
    [activeProfile.gifEvents, canAddGifItems, removeGifItem]
  );

  const playFixedIndependentSound = useCallback(
    (eventIndex) => {
      const event = activeProfile.soundEvents[eventIndex];
      if (!event || !isPlayingRef.current) return;
      if (independentSoundIdRef.current) return;
      const soundPath = INDEPENDENT_SOUNDS[event.key];
      if (!soundPath) return;

      const id = `sound-${eventIndex}-${Date.now()}`;
      const audio = new Audio(soundPath);
      audio.volume = 0.7;
      audioRefs.current[id] = audio;
      independentSoundIdRef.current = id;

      audio.play().catch(() => {
        if (independentSoundIdRef.current === id) independentSoundIdRef.current = null;
        delete audioRefs.current[id];
      });

      const stopTimer = setTimeout(() => {
        if (audioRefs.current[id]) {
          audio.pause();
          audio.currentTime = 0;
          audio.src = "";
          delete audioRefs.current[id];
        }
        if (independentSoundIdRef.current === id) independentSoundIdRef.current = null;
      }, event.duration);

      eventTimers.current.push(stopTimer);
    },
    [activeProfile.soundEvents]
  );

  const scheduleFixedEvents = useCallback(() => {
    clearEventTimers();
    activeProfile.gifEvents.forEach((event, index) => {
      const timerId = setTimeout(() => showFixedGifEvent(index), event.at);
      eventTimers.current.push(timerId);
    });
    activeProfile.soundEvents.forEach((event, index) => {
      const timerId = setTimeout(() => playFixedIndependentSound(index), event.at);
      eventTimers.current.push(timerId);
    });
  }, [activeProfile.gifEvents, activeProfile.soundEvents, clearEventTimers, playFixedIndependentSound, showFixedGifEvent]);

  const flushCurrentTrial = useCallback(() => {
    const t = currentTrial.current;
    if (t) {
      trialLog.current.push({
        trialNumber: t.trialNumber,
        section: t.section,
        isTarget: t.isTarget,
        shownShape: t.shownShape,
        shownColor: t.shownColor,
        targetShape: t.targetShape,
        targetColor: t.targetColor,
        responded: t.responded,
        reactionTime: t.reactionTime || 0,
        responseCount: t.responses.length
      });
    }
    currentTrial.current = null;
  }, []);

  const finishTest = useCallback(() => {
    clearTimeout(timer.current);
    clearTimeout(testClockTimer.current);
    flushCurrentTrial();
    setScene(null);
    isPlayingRef.current = false;
    stopAllSystems();
    setSessionStage("finished");
  }, [flushCurrentTrial, stopAllSystems]);

  const createNonTargetObject = useCallback(() => {
    const current = targetRef.current;
    let obj;
    do {
      obj = { shape: randomItemSeeded(SHAPES), color: randomItemSeeded(COLORS) };
    } while (obj.shape === current.shape && obj.color === current.color);
    return obj;
  }, []);

  const nextTrial = useCallback(() => {
    if (!isPlayingRef.current) return;
    const elapsed = getElapsedMs();
    if (elapsed >= activeProfile.durationMs) {
      finishTest();
      return;
    }
    const phase = getPhaseInfo(elapsed);
    const trialNumber = trialLog.current.length + 1;
    const isTarget = seededRandom() < activeProfile.targetProbability;
    const currentTarget = targetRef.current;
    const shownObject = isTarget ? { ...currentTarget } : createNonTargetObject();

    currentTrial.current = {
      trialNumber,
      section: phase.name,
      isTarget,
      shownShape: shownObject.shape,
      shownColor: shownObject.color,
      targetShape: currentTarget.shape,
      targetColor: currentTarget.color,
      responded: false,
      reactionTime: 0,
      responses: [],
      startTime: performance.now()
    };

    setScene({ shape: shownObject.shape, color: shownObject.color, isTarget });

    timer.current = setTimeout(() => {
      setScene(null);
      const t = currentTrial.current;
      if (t) {
        trialLog.current.push({
          trialNumber: t.trialNumber,
          section: t.section,
          isTarget: t.isTarget,
          shownShape: t.shownShape,
          shownColor: t.shownColor,
          targetShape: t.targetShape,
          targetColor: t.targetColor,
          responded: t.responded,
          reactionTime: t.reactionTime || 0,
          responseCount: t.responses.length
        });
      }
      currentTrial.current = null;
      const nextPhase = getPhaseInfo();
      timer.current = setTimeout(nextTrial, nextPhase.gap);
    }, phase.stimulus);
  }, [activeProfile.durationMs, activeProfile.targetProbability, createNonTargetObject, finishTest, getElapsedMs, getPhaseInfo]);

  const handleResponse = useCallback(() => {
    if (!currentTrial.current) return;
    const now = performance.now();
    currentTrial.current.responses.push(now);
    if (!currentTrial.current.responded) {
      currentTrial.current.responded = true;
      currentTrial.current.reactionTime = now - currentTrial.current.startTime;
    }
  }, []);

  const registerResponse = useCallback(() => {
    const now = performance.now();
    if (now - lastInputTime.current < 120) return;
    lastInputTime.current = now;
    handleResponse();
  }, [handleResponse]);

  const startTest = useCallback(() => {
    resetDeterministicSeed();
    trialLog.current = [];
    currentTrial.current = null;
    lastInputTime.current = 0;
    clearTimeout(timer.current);
    clearTimeout(testClockTimer.current);
    stopAllSystems();
    setScene(null);
    testStartTimeRef.current = performance.now();
    isPlayingRef.current = true;
    setSessionStage("running");
    scheduleFixedEvents();
    testClockTimer.current = setTimeout(() => finishTest(), activeProfile.durationMs);
  }, [activeProfile.durationMs, finishTest, scheduleFixedEvents, stopAllSystems]);

  const resetSession = useCallback(() => {
    clearTimeout(timer.current);
    clearTimeout(testClockTimer.current);
    isPlayingRef.current = false;
    stopAllSystems();
    trialLog.current = [];
    currentTrial.current = null;
    lastInputTime.current = 0;
    testStartTimeRef.current = 0;
    setScene(null);
    resetDeterministicSeed();
    createNewTarget();
    setSessionStage("idle");
  }, [createNewTarget, stopAllSystems]);

  const hardResetTarget = useCallback(() => {
    clearTimeout(timer.current);
    clearTimeout(testClockTimer.current);
    isPlayingRef.current = false;
    stopAllSystems();
    trialLog.current = [];
    currentTrial.current = null;
    lastInputTime.current = 0;
    testStartTimeRef.current = 0;
    setScene(null);
    targetRef.current = null;
    setTarget(null);
    setSessionStage("idle");
  }, [stopAllSystems]);

  useEffect(() => {
    createNewTarget();
    return () => {
      clearTimeout(timer.current);
      clearTimeout(testClockTimer.current);
      stopAllSystems();
    };
  }, [activeProfile.key, createNewTarget, stopAllSystems]);

  useEffect(() => {
    if (sessionStage !== "running" || !targetRef.current) return;
    nextTrial();
    return () => clearTimeout(timer.current);
  }, [sessionStage, nextTrial]);

  useEffect(() => {
    const handleKeyDown = (event) => {
      const activeElement = document.activeElement;
      const isTypingField =
        activeElement &&
        (activeElement.tagName === "INPUT" ||
          activeElement.tagName === "TEXTAREA" ||
          activeElement.tagName === "SELECT" ||
          activeElement.isContentEditable);
      if (event.code === "Space" && !isTypingField && isPlayingRef.current) {
        event.preventDefault();
        registerResponse();
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [registerResponse]);

  const getTrialLogs = useCallback(() => trialLog.current.slice(), []);

  return {
    target,
    scene,
    gifDistractors,
    sessionStage,
    setSessionStage,
    startTest,
    finishTest,
    resetSession,
    hardResetTarget,
    registerResponse,
    createNewTarget,
    getTrialLogs
  };
}

