import { useState } from "react";
import { supabase } from "../../lib/supabase.js";
import { inputStyle, shell } from "../../components/ui.jsx";

export function AuthPage({ onAuthSuccess }) {
  const [mode, setMode] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const isLogin = mode === "login";

  const handleSubmit = async (event) => {
    event.preventDefault();
    setMessage("");
    const normalizedEmail = email.trim().toLowerCase();
    if (!normalizedEmail || !password) {
      setMessage("E-posta ve şifre zorunludur.");
      return;
    }
    if (password.length < 6) {
      setMessage("Şifre en az 6 karakter olmalıdır.");
      return;
    }
    setLoading(true);
    try {
      if (isLogin) {
        const { data, error } = await supabase.auth.signInWithPassword({
          email: normalizedEmail,
          password
        });
        if (error) {
          if (
            error.message?.toLowerCase().includes("email not confirmed") ||
            error.message?.toLowerCase().includes("not confirmed")
          ) {
            setMessage("Hesabınız henüz doğrulanmamış. Lütfen e-postanızdaki doğrulama linkine tıklayın.");
          } else {
            setMessage(error.message);
          }
          return;
        }
        onAuthSuccess(data.user ?? null);
        return;
      }
      const { data, error } = await supabase.auth.signUp({
        email: normalizedEmail,
        password,
        options: { data: { email: normalizedEmail } }
      });
      if (error) {
        setMessage(error.message);
        return;
      }
      if (data.user && data.session) {
        onAuthSuccess(data.user);
        return;
      }
      setMessage("Kayıt oluşturuldu. E-posta doğrulaması açıksa gelen kutunuzu kontrol edin, ardından giriş yapın.");
      setMode("login");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={shell}>
      <form
        onSubmit={handleSubmit}
        style={{
          width: "100%",
          maxWidth: 430,
          background: "white",
          borderRadius: 24,
          padding: 34,
          boxShadow: "0 18px 50px rgba(15,23,42,0.12)"
        }}
      >
        <h1 style={{ marginTop: 0, marginBottom: 8, textAlign: "center" }}>{isLogin ? "Giriş Yap" : "Üye Ol"}</h1>
        <p style={{ color: "#142440", textAlign: "center", fontWeight: "bold", fontSize: 18, marginBottom: 26 }}>
          FocusProLab
        </p>
        <label style={{ fontWeight: "bold", color: "#0F172A" }}>E-posta</label>
        <input
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          placeholder="ornek@mail.com"
          autoComplete="email"
          style={inputStyle}
        />
        <label style={{ fontWeight: "bold", color: "#0F172A" }}>Şifre</label>
        <input
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          placeholder="En az 6 karakter"
          autoComplete={isLogin ? "current-password" : "new-password"}
          style={inputStyle}
        />
        {message && (
          <div
            style={{
              color: "#DC2626",
              background: "#FEF2F2",
              border: "1px solid #FECACA",
              borderRadius: 12,
              padding: 10,
              marginBottom: 14
            }}
          >
            {message}
          </div>
        )}
        <button
          type="submit"
          disabled={loading}
          style={{
            width: "100%",
            background: "#142440",
            color: "white",
            border: "none",
            borderRadius: 14,
            padding: "15px 34px",
            fontSize: 16,
            cursor: loading ? "not-allowed" : "pointer",
            opacity: loading ? 0.7 : 1,
            fontWeight: "bold"
          }}
        >
          {loading ? "İşleniyor..." : isLogin ? "Giriş Yap" : "Üye Ol"}
        </button>
        <button
          type="button"
          onClick={() => {
            setMode(isLogin ? "register" : "login");
            setMessage("");
          }}
          style={{
            width: "100%",
            marginTop: 14,
            border: "none",
            background: "transparent",
            color: "#142440",
            fontWeight: "bold",
            cursor: "pointer"
          }}
        >
          {isLogin ? "Hesabınız yok mu? Üye Ol" : "Zaten hesabınız var mı? Giriş Yap"}
        </button>
      </form>
    </div>
  );
}

