import { calculateAgeFromBirthDate, getProfileKeyByAge } from "../../domain/participant.js";
import { FormField, inputStyle } from "../../components/ui.jsx";

const initialParticipant = {
  name: "",
  birthDate: "",
  age: "",
  gender: "",
  reason: "",
  consent: false,
  profileKey: "adult"
};

export function ParticipantForm({ participant, setParticipant, onSubmit, formError }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const ageNumber = calculateAgeFromBirthDate(participant.birthDate);
    if (!participant.name.trim()) {
      onSubmit({ error: "Lütfen ad soyad bilgisini girin." });
      return;
    }
    if (ageNumber === null || ageNumber < 6 || ageNumber > 99) {
      onSubmit({ error: "Lütfen 6-99 yaş aralığına uygun geçerli bir doğum tarihi girin." });
      return;
    }
    if (!participant.gender) {
      onSubmit({ error: "Lütfen cinsiyet bilgisini seçin." });
      return;
    }
    const profileKey = getProfileKeyByAge(ageNumber);
    if ((profileKey === "child" || profileKey === "teen") && !participant.consent) {
      onSubmit({ error: "Çocuk ve ergen kullanıcılar için veli/onam kutusu işaretlenmelidir." });
      return;
    }
    onSubmit({
      error: null,
      payload: {
        ...participant,
        age: String(ageNumber),
        profileKey
      }
    });
  };

  return (
    <form
      onSubmit={handleSubmit}
      style={{
        width: "100%",
        maxWidth: 620,
        background: "white",
        borderRadius: 24,
        padding: 34,
        boxShadow: "0 18px 50px rgba(15,23,42,0.12)"
      }}
    >
      <h1 style={{ marginTop: 0, textAlign: "center" }}>Katılımcı Bilgileri</h1>
      <p style={{ color: "#142440", textAlign: "center", lineHeight: 1.5, fontWeight: "bold", fontSize: 18 }}>
        FocusProLab
      </p>
      <FormField label="Ad Soyad">
        <input
          value={participant.name}
          onChange={(e) => setParticipant((p) => ({ ...p, name: e.target.value }))}
          placeholder="Ad Soyad"
          autoComplete="name"
          style={inputStyle}
        />
      </FormField>
      <FormField label="Doğum Tarihi">
        <input
          type="date"
          value={participant.birthDate}
          onChange={(e) => {
            const birthDate = e.target.value;
            const calculatedAge = calculateAgeFromBirthDate(birthDate);
            const profileKey = calculatedAge === null ? "adult" : getProfileKeyByAge(calculatedAge);
            setParticipant((prev) => ({
              ...prev,
              birthDate,
              age: calculatedAge === null ? "" : String(calculatedAge),
              profileKey,
              consent: profileKey === "adult" ? false : prev.consent
            }));
          }}
          style={inputStyle}
        />
      </FormField>
      <FormField label="Cinsiyet *">
        <select
          value={participant.gender}
          onChange={(e) => setParticipant((p) => ({ ...p, gender: e.target.value }))}
          style={inputStyle}
          required
        >
          <option value="">Seçiniz</option>
          <option value="Kadın">Kadın</option>
          <option value="Erkek">Erkek</option>
        </select>
      </FormField>
      <FormField label="Test Nedeni / Not (opsiyonel)">
        <textarea
          value={participant.reason}
          onChange={(e) => setParticipant((p) => ({ ...p, reason: e.target.value }))}
          placeholder="Örn. dikkat performansı ön değerlendirmesi"
          style={{ ...inputStyle, minHeight: 78, resize: "vertical" }}
        />
      </FormField>
      {(participant.profileKey === "child" || participant.profileKey === "teen") && (
        <label style={{ display: "flex", gap: 10, alignItems: "flex-start", marginTop: 14, color: "#334155", lineHeight: 1.4 }}>
          <input
            type="checkbox"
            checked={participant.consent}
            onChange={(e) => setParticipant((p) => ({ ...p, consent: e.target.checked }))}
            style={{ marginTop: 3 }}
          />
          <span>Çocuk/ergen katılımcı için veli/uzman bilgilendirme ve onamının alındığını kabul ediyorum.</span>
        </label>
      )}
      {formError && (
        <div style={{ color: "#DC2626", background: "#FEF2F2", border: "1px solid #FECACA", borderRadius: 12, padding: 10, marginTop: 14 }}>
          {formError}
        </div>
      )}
      <button
        type="submit"
        style={{
          width: "100%",
          marginTop: 20,
          background: "#142440",
          color: "white",
          border: "none",
          borderRadius: 14,
          padding: "15px 34px",
          fontSize: 17,
          cursor: "pointer",
          fontWeight: "bold"
        }}
      >
        Devam Et
      </button>
    </form>
  );
}

export { initialParticipant };

import { calculateAdvancedMetrics, formatDurationSeconds, getPhaseComment, getRiskLevel } from "../../domain/metrics.js";

export function getScoresFromLogs(logs, lateResponseMs) {
  const m = calculateAdvancedMetrics(logs, lateResponseMs);
  return {
    attention: Math.round(m.attentionScore),
    timing: Math.round(m.processingSpeedScore),
    impulsivity: Math.round(m.impulseControlScore),
    hyperactivity: Math.round(m.consistencyScore),
    overall: Math.round(m.overallScore),
    raw: m
  };
}

export function getLevel(score) {
  if (score >= 85) return 1;
  if (score >= 70) return 2;
  if (score >= 55) return 3;
  return 4;
}

export function getLevelText(score) {
  const level = getLevel(score);
  if (level === 1) return "İyi Performans";
  if (level === 2) return "Standart Performans";
  if (level === 3) return "Düşük Performans";
  return "Performansta Zorluk";
}

export function getScoreColor(score) {
  const level = getLevel(score);
  if (level === 1) return "#16A34A";
  if (level === 2) return "#65A30D";
  if (level === 3) return "#F59E0B";
  return "#DC2626";
}

export function formatRate(value) {
  return `%${Number(value || 0).toFixed(1)}`;
}

export function getProfessionalSummary(scores, metrics) {
  const riskLevel = getRiskLevel(metrics);
  return [
    `Genel risk düzeyi: ${riskLevel}. Genel performans skoru ${scores.overall}/100 olarak hesaplandı.`,
    `Dikkat skoru ${scores.attention}/100, işlem hızı skoru ${scores.timing}/100, dürtü kontrol skoru ${scores.impulsivity}/100 ve tutarlılık skoru ${scores.hyperactivity}/100 düzeyindedir.`,
    `Omission oranı ${formatRate(metrics.omissionRate)}, false alarm oranı ${formatRate(metrics.falseAlarmRate)}, geç yanıt oranı ${formatRate(metrics.lateRate)} ve çoklu basma oranı ${formatRate(metrics.multiPressRate)} olarak hesaplandı.`,
    `Ortalama RT ${metrics.avgReaction} ms, median RT ${metrics.medianReaction} ms ve RT standart sapması ${metrics.rtStd} ms'dir.`,
    `d-prime ${metrics.dPrime.toFixed(2)} olup hedef uyaranı hedef dışı uyarandan ayırt etme performansını gösteren ek bir sinyal ayırt etme indeksidir.`
  ].join("\n\n");
}

export function getPerformanceScoreSeries(logs, lateResponseMs) {
  const attentionData = [];
  const timingData = [];
  const impulsivityData = [];
  const hyperactivityData = [];
  logs.forEach((_, index) => {
    const partialMetrics = calculateAdvancedMetrics(logs.slice(0, index + 1), lateResponseMs);
    attentionData.push(Math.round(partialMetrics.attentionScore));
    timingData.push(Math.round(partialMetrics.processingSpeedScore));
    impulsivityData.push(Math.round(partialMetrics.impulseControlScore));
    hyperactivityData.push(Math.round(partialMetrics.consistencyScore));
  });
  return { attentionData, timingData, impulsivityData, hyperactivityData };
}

export function getSectionSummary(logs, profile) {
  return profile.phases.map((phase) => {
    const list = logs.filter((t) => t.section === phase.name);
    const m = calculateAdvancedMetrics(list, profile.lateResponseMs);
    return {
      section: phase.name,
      totalTrials: m.totalTrials,
      attentionScore: Math.round(m.attentionScore),
      timingScore: Math.round(m.processingSpeedScore),
      impulsivityScore: Math.round(m.impulseControlScore),
      hyperactivityScore: Math.round(m.consistencyScore),
      accuracy: Math.round(m.accuracy),
      omissionRate: m.omissionRate,
      falseAlarmRate: m.falseAlarmRate,
      medianReaction: m.medianReaction,
      overallScore: m.overallScore,
      comment: getPhaseComment(phase.name, m.overallScore)
    };
  });
}

export function generateSmartComment(scores, metrics, profile) {
  const comments = [];
  comments.push(
    `Test ${metrics.totalTrials} deneme üzerinden tamamlandı. Genel doğruluk oranı %${metrics.accuracy}, ortalama tepki süresi ${metrics.avgReaction} ms, median tepki süresi ${metrics.medianReaction} ms ve RT değişkenliği ${metrics.rtStd} ms olarak hesaplandı.`
  );
  comments.push(
    `Genel performans skoru ${scores.overall}/100, dikkat skoru ${scores.attention}/100, işlem hızı skoru ${scores.timing}/100, dürtü kontrol skoru ${scores.impulsivity}/100 ve tutarlılık skoru ${scores.hyperactivity}/100 olarak hesaplandı.`
  );
  comments.push(
    `Test süresi seçilen profile göre ${formatDurationSeconds(profile.durationMs)} saniyedir. Kullanılan profil: ${profile.label}. Fazlar yaş grubuna göre uyarlanmış dikkat, hız baskısı ve çeldirici aşamalarından oluşur. Uyaran dizisi deterministik olarak üretilir.`
  );
  comments.push(`Ön değerlendirme risk düzeyi: ${getRiskLevel(metrics)}.`);
  if (metrics.flags.length > 0) {
    comments.push("Öne çıkan bulgular: " + metrics.flags.join("; ") + ".");
  } else {
    comments.push("Belirgin klinik risk bayrağı oluşturan bir performans paterni izlenmemiştir.");
  }
  comments.push(
    `d-prime değeri ${metrics.dPrime.toFixed(2)} olarak hesaplanmıştır. Bu değer hedef uyaranı hedef olmayan uyarandan ayırt etme kapasitesi için ek bir göstergedir.`
  );
  comments.push(
    "Not: Bu uygulama klinik tanı koymaz. Sonuçlar yalnızca dikkat, tepki süresi ve dürtü kontrolü alanlarında ön değerlendirme amacıyla kullanılmalıdır."
  );
  return comments.join(" ");
}

import pdfMake from "pdfmake/build/pdfmake";
import pdfFonts from "pdfmake/build/vfs_fonts";
import { getShapeSvg } from "../test/shapeUtils.js";
import {
  formatRate,
  getLevel,
  getLevelText,
  getProfessionalSummary,
  getScoreColor,
  getScoresFromLogs,
  getSectionSummary
} from "./scoring.js";
import { generateSmartComment } from "./scoring.js";

pdfMake.vfs = pdfFonts.pdfMake ? pdfFonts.pdfMake.vfs : pdfFonts.vfs;

export function buildPdfDefinition({ participant, profile, trialLogs, chartImageDataUrl, targetShape, targetColor }) {
  const scoresBundle = getScoresFromLogs(trialLogs, profile.lateResponseMs);
  const scores = {
    attention: scoresBundle.attention,
    timing: scoresBundle.timing,
    impulsivity: scoresBundle.impulsivity,
    hyperactivity: scoresBundle.hyperactivity,
    overall: scoresBundle.overall
  };
  const metrics = scoresBundle.raw;
  const riskLevel = metrics.overallScore < 60 || metrics.omissionRate >= 25 ? "Yüksek" : metrics.overallScore < 75 ? "Orta" : "Düşük";
  const professionalSummary = getProfessionalSummary(scores, metrics);
  const sections = getSectionSummary(trialLogs, profile);

  return {
    pageSize: "A4",
    pageMargins: [36, 36, 36, 36],
    defaultStyle: { font: "Roboto", fontSize: 10 },
    content: [
      {
        text: "Dikkat, Tepki Süresi ve Dürtü Kontrolü Ön Değerlendirme Raporu",
        fontSize: 20,
        bold: true,
        color: "#142440",
        margin: [0, 0, 0, 6]
      },
      {
        text: "Bilgisayarlı sürekli performans / hedef-hedef dışı uyaran görevi — ön analiz",
        fontSize: 11,
        color: "#475569",
        margin: [0, 0, 0, 20]
      },
      {
        columns: [
          {
            width: "*",
            stack: [
              { text: "Rapor Tarihi: " + new Date().toLocaleDateString("tr-TR") },
              { text: "Katılımcı: " + participant.name, margin: [0, 6, 0, 0] },
