        fontSize: 10,
        margin: [0, 0, 0, 14]
      },
      { text: "Otomatik Yorum", fontSize: 15, bold: true, margin: [0, 0, 0, 8] },
      {
        text: generateSmartComment(scores, metrics, profile),
        fontSize: 10,
        lineHeight: 1.3,
        margin: [0, 0, 0, 40]
      },
      {
        text: "Not: Bu uygulama klinik tanı koymaz. Sonuçlar yalnızca klinik ön değerlendirme ve performans analizi amacıyla kullanılmalıdır.",
        fontSize: 8,
        color: "#64748B"
      }
    ]
  };
}

export function createPdfBlob(docDefinition) {
  return new Promise((resolve, reject) => {
    try {
      pdfMake.createPdf(docDefinition).getBlob((blob) => resolve(blob));
    } catch (e) {
      reject(e);
    }
  });
}

