import {
  CategoryScale,
  Chart as ChartJS,
  Legend,
  LinearScale,
  LineElement,
  PointElement,
  Tooltip
} from "chart.js";

ChartJS.register(LineElement, PointElement, LinearScale, CategoryScale, Legend, Tooltip);

import "./chartSetup.js";
import { forwardRef, useMemo } from "react";
import { Line } from "react-chartjs-2";
import { getPerformanceScoreSeries } from "./scoring.js";

export const PerformanceChart = forwardRef(function PerformanceChart({ trialLogs, lateResponseMs }, ref) {
  const data = useMemo(() => {
    const labels = trialLogs.map((t) => t.trialNumber);
    const series = getPerformanceScoreSeries(trialLogs, lateResponseMs);
    return {
      labels,
      datasets: [
        { label: "Dikkat", data: series.attentionData, borderColor: "#2563EB", backgroundColor: "#2563EB", tension: 0.25, pointRadius: 2 },
        { label: "İşlem Hızı", data: series.timingData, borderColor: "#16A34A", backgroundColor: "#16A34A", tension: 0.25, pointRadius: 2 },
        { label: "Dürtü Kontrol", data: series.impulsivityData, borderColor: "#DC2626", backgroundColor: "#DC2626", tension: 0.25, pointRadius: 2 },
        { label: "Tutarlılık", data: series.hyperactivityData, borderColor: "#F59E0B", backgroundColor: "#F59E0B", tension: 0.25, pointRadius: 2 }
      ]
    };
  }, [trialLogs, lateResponseMs]);

  const options = useMemo(
    () => ({
      responsive: true,
      maintainAspectRatio: false,
      animation: false,
      plugins: { legend: { display: true, position: "bottom" }, tooltip: { enabled: true } },
      scales: { y: { min: 0, max: 100, ticks: { stepSize: 10 } } }
    }),
    []
  );

  return <Line ref={ref} data={data} options={options} />;
});

import { supabase } from "../../lib/supabase.js";

export async function uploadReportPdf({ userId, fileName, blob }) {
  const { error: uploadError } = await supabase.storage.from("reports").upload(fileName, blob, {
    contentType: "application/pdf",
    upsert: false
  });
  if (uploadError) throw uploadError;

  const { error: insertError } = await supabase.from("reports").insert({
    user_id: userId,
    file_name: fileName,
    created_at: new Date().toISOString()
  });
  if (insertError) throw insertError;
}

import { useEffect, useRef, useState } from "react";
import { AuthPage } from "./features/auth/AuthPage.jsx";
import { initialParticipant, ParticipantForm } from "./features/participant/ParticipantForm.jsx";
import { ShapeView } from "./features/test/ShapeView.jsx";
import { useAttentionTest } from "./features/test/useAttentionTest.js";
import { getProfile } from "./features/test/profiles.js";
import { supabase, supabaseConfigured } from "./lib/supabase.js";
import { FormField, MetricBox, ScoreBox, inputStyle, shell } from "./components/ui.jsx";
import { PerformanceChart } from "./features/report/PerformanceChart.jsx";
import { buildPdfDefinition, createPdfBlob } from "./features/report/buildPdfDocument.js";
import { uploadReportPdf } from "./features/report/uploadReport.js";
import { generateSmartComment, getScoreColor, getScoresFromLogs } from "./features/report/scoring.js";

const DEMO_USER = { id: "00000000-0000-0000-0000-000000000001", email: "demo@yerel.focusprolab" };

export default function App() {
  const [authUser, setAuthUser] = useState(null);
  const [authLoading, setAuthLoading] = useState(supabaseConfigured);
  const [participant, setParticipant] = useState(initialParticipant);
  const [formError, setFormError] = useState("");
  const [step, setStep] = useState("participant");
  const [reportLogs, setReportLogs] = useState([]);
  const chartRef = useRef(null);

  const activeProfile = getProfile(participant.profileKey);
  const {
    target,
    scene,
    gifDistractors,
    sessionStage,
    startTest,
    resetSession,
    hardResetTarget,
    registerResponse,
    getTrialLogs
  } = useAttentionTest(activeProfile);

  useEffect(() => {
    if (!supabaseConfigured) {
      setAuthUser(DEMO_USER);
      setAuthLoading(false);
      return undefined;
    }
    let mounted = true;
    supabase.auth.getUser().then(({ data }) => {
      if (!mounted) return;
      setAuthUser(data.user ?? null);
      setAuthLoading(false);
    });
    const { data: listener } = supabase.auth.onAuthStateChange((_event, session) => {
      setAuthUser(session?.user ?? null);
      setAuthLoading(false);
    });
    return () => {
      mounted = false;
      listener?.subscription?.unsubscribe();
    };
  }, []);

  useEffect(() => {
    if (sessionStage === "finished" && step === "play") {
      setStep("complete");
    }
  }, [sessionStage, step]);

  const handleSignOut = async () => {
    if (supabaseConfigured) await supabase.auth.signOut();
    setAuthUser(supabaseConfigured ? null : DEMO_USER);
    hardResetTarget();
    setParticipant(initialParticipant);
    setFormError("");
    setReportLogs([]);
    setStep("participant");
  };

  const handleParticipantResult = (result) => {
    if (result.error) {
      setFormError(result.error);
      return;
    }
    setFormError("");
    setParticipant(result.payload);
    setStep("briefing");
  };

  const handleStartTestClick = () => {
    setStep("play");
    startTest();
  };

  const goToReport = () => {
    setReportLogs(getTrialLogs());
    setStep("report");
  };

  const handleDownloadReport = async () => {
    if (!target) return;
    const chartImage = chartRef.current?.canvas?.toDataURL("image/png", 1.0);
    const doc = buildPdfDefinition({
      participant,
      profile: activeProfile,
      trialLogs: reportLogs,
      chartImageDataUrl: chartImage,
      targetShape: target.shape,
      targetColor: target.color
    });
    const blob = await createPdfBlob(doc);
    const fileName = `report_${authUser.id}_${Date.now()}.pdf`;

    if (supabaseConfigured && authUser && authUser.id !== DEMO_USER.id) {
      try {
        await uploadReportPdf({ userId: authUser.id, fileName, blob });
      } catch (err) {
        console.error(err);
        alert("PDF depolamaya yüklenemedi; yine de indirme deneniyor.");
      }
    }

    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = fileName;
    a.click();
    URL.revokeObjectURL(url);
  };

  const scoresBundle = reportLogs.length ? getScoresFromLogs(reportLogs, activeProfile.lateResponseMs) : null;
  const scores = scoresBundle
    ? {
        attention: scoresBundle.attention,
        timing: scoresBundle.timing,
        impulsivity: scoresBundle.impulsivity,
        hyperactivity: scoresBundle.hyperactivity,
        overall: scoresBundle.overall
      }
    : null;
  const metrics = scoresBundle?.raw;

  if (authLoading) {
    return (
      <div style={{ ...shell, fontFamily: "system-ui, sans-serif" }}>
        FocusProLab yükleniyor...
      </div>
    );
  }

  if (!authUser) {
    return (
      <>
        {!supabaseConfigured && (
          <div
            style={{
              background: "#FEF3C7",
              color: "#92400E",
              padding: "10px 16px",
              textAlign: "center",
              fontSize: 14
            }}
          >
            Supabase ortam değişkenleri tanımlı değil (.env). Kimlik doğrulama kapalı; yerel demo hesabı ile çalışıyorsunuz.
          </div>
        )}
        <AuthPage onAuthSuccess={(user) => setAuthUser(user)} />
      </>
    );
  }

  return (
    <div style={shell}>
      {!supabaseConfigured && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            right: 0,
            background: "#FEF3C7",
            color: "#92400E",
            padding: "8px 12px",
            textAlign: "center",
            fontSize: 13,
            zIndex: 100
          }}
        >
          Demo modu: Raporlar buluta yüklenmez. Üretim için .env içinde VITE_SUPABASE_URL ve VITE_SUPABASE_ANON_KEY ayarlayın.
        </div>
      )}
      <div style={{ position: "fixed", top: supabaseConfigured ? 14 : 40, right: 18, zIndex: 30, display: "flex", alignItems: "center", gap: 10 }}>
        <span
          style={{
            fontSize: 12,
            color: "#475569",
            background: "#F8FAFC",
            border: "1px solid #E2E8F0",
            borderRadius: 999,
            padding: "7px 10px"
          }}
        >
          {authUser.email}
        </span>
        <button
          type="button"
          onClick={handleSignOut}
          style={{
            border: "none",
            borderRadius: 999,
            background: "#E5E7EB",
            color: "#111827",
            padding: "8px 12px",
            cursor: "pointer",
            fontWeight: "bold"
          }}
        >
          {supabaseConfigured ? "Çıkış Yap" : "Oturumu Sıfırla"}
        </button>
      </div>

      {step === "participant" && (
        <ParticipantForm
          participant={participant}
          setParticipant={setParticipant}
          formError={formError}
          onSubmit={handleParticipantResult}
        />
      )}

      {step === "briefing" && target && (
        <div
          style={{
            width: "100%",
            maxWidth: 900,
            background: "white",
            borderRadius: 24,
            padding: 36,
            boxShadow: "0 18px 50px rgba(15,23,42,0.12)",
            textAlign: "center"
          }}
        >
          <h1 style={{ marginTop: 0 }}>Dikkat Performans Testi</h1>
          <div style={{ marginBottom: 18, color: "#475569" }}>
            <strong>Katılımcı:</strong> {participant.name} &nbsp;|&nbsp;
            <strong>Yaş:</strong> {participant.age} &nbsp;|&nbsp;
            <strong>Test Grubu:</strong> {activeProfile.label} ({activeProfile.ageRange})
          </div>
          <p style={{ fontSize: 17, color: "#475569" }}>
            Aşağıdaki nesne hedef olarak seçildi. Test boyunca yalnızca bu şekil ve bu renk <strong>birlikte</strong> göründüğünde{" "}
            <strong>SPACE</strong> tuşuna basın. Dokunmatik ekranda alana dokunma da yanıt sayılır.
          </p>
          <div
            style={{
              margin: "30px auto",
              width: 190,
              height: 190,
              borderRadius: 28,
              border: "3px solid #142440",
              background: "#F8FAFC",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              boxShadow: "0 10px 30px rgba(15,23,42,0.12)"
            }}
          >
            <ShapeView shape={target.shape} color={target.color} size={110} />
          </div>
          <button
            type="button"
            onClick={handleStartTestClick}
            style={{
              background: "#142440",
              color: "white",
              border: "none",
              borderRadius: 14,
              padding: "15px 34px",
              fontSize: 17,
              cursor: "pointer",
              fontWeight: "bold"
            }}
          >
            Teste Başla
          </button>
        </div>
      )}

      {step === "play" && sessionStage === "running" && (
        <div
          role="presentation"
          onClick={registerResponse}
          onTouchStart={registerResponse}
          style={{
            width: "96vw",
            maxWidth: 1180,
            height: "78vh",
            minHeight: 560,
            background: "#FFFFFF",
            borderRadius: 24,
            boxShadow: "0 18px 50px rgba(15,23,42,0.12)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            position: "relative",
            overflow: "hidden",
            cursor: "pointer",
            touchAction: "manipulation",
            userSelect: "none"
          }}
        >
          {gifDistractors.map((item) => (
            <img
              key={item.id}
              src={item.gif}
              alt=""
              onError={(e) => {
                e.target.style.display = "none";
              }}
              style={{
                position: "absolute",
                left: `${item.left}%`,
                top: `${item.top}%`,
                width: item.size,
                maxWidth: "30%",
                maxHeight: "38%",
                height: "auto",
                transform: "translate(-50%, -50%)",
                pointerEvents: "none",
                zIndex: 1,
                objectFit: "contain"
              }}
            />
          ))}
          {scene && (
            <div style={{ zIndex: 5 }}>
              <ShapeView shape={scene.shape} color={scene.color} size={170} />
            </div>
          )}
        </div>
      )}

      {step === "complete" && target && (
        <div
          style={{
            width: "100%",
            maxWidth: 720,
            background: "white",
            borderRadius: 24,
            padding: 38,
            boxShadow: "0 18px 50px rgba(15,23,42,0.12)",
            textAlign: "center"
          }}
        >
          <h1 style={{ marginTop: 0, marginBottom: 10 }}>Test Bitti</h1>
          <p style={{ color: "#475569", fontSize: 17, lineHeight: 1.5, marginBottom: 26 }}>
            Sonuçları ve raporu görmek için devam edin.
          </p>
          <button
            type="button"
            onClick={goToReport}
            style={{
              background: "#142440",
              color: "white",
              border: "none",
              borderRadius: 14,
              padding: "15px 34px",
              fontSize: 16,
              cursor: "pointer",
              fontWeight: "bold"
            }}
          >
            Raporu Görüntüle
          </button>
        </div>
      )}

      {step === "report" && target && scores && metrics && (
        <div
          style={{
            width: "100%",
            maxWidth: 980,
            background: "white",
            borderRadius: 24,
            padding: 34,
            boxShadow: "0 18px 50px rgba(15,23,42,0.12)"
          }}
        >
          <h1 style={{ textAlign: "center", marginTop: 0 }}>Profesyonel Rapor</h1>
          <div style={{ textAlign: "center", color: "#475569", marginBottom: 14 }}>
            <strong>{participant.name}</strong> | Yaş: {participant.age} | Test Grubu: {activeProfile.label}
          </div>
          <div style={{ textAlign: "center", marginBottom: 20 }}>
            <strong>Hedef Nesne:</strong>
            <div style={{ marginTop: 12 }}>
              <ShapeView shape={target.shape} color={target.color} size={60} />
            </div>
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(4, 1fr)",
              gap: 14,
              marginTop: 24,
              marginBottom: 22
            }}
          >
            <ScoreBox title="Dikkat" value={scores.attention} color={getScoreColor(scores.attention)} />
            <ScoreBox title="İşlem Hızı" value={scores.timing} color={getScoreColor(scores.timing)} />
            <ScoreBox title="Dürtüsellik" value={scores.impulsivity} color={getScoreColor(scores.impulsivity)} />
            <ScoreBox title="Tutarlılık" value={scores.hyperactivity} color={getScoreColor(scores.hyperactivity)} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 14, marginBottom: 28 }}>
            <MetricBox title="Genel Skor" value={`${scores.overall}/100`} />
            <MetricBox title="Doğruluk" value={`%${metrics.accuracy}`} />
            <MetricBox title="Median RT" value={`${metrics.medianReaction} ms`} />
            <MetricBox title="d-prime" value={metrics.dPrime.toFixed(2)} />
          </div>
          <h3>Performans Grafiği</h3>
