export function ageFromBirthDate(isoDate) {
  if (!isoDate) return null;
  const d = new Date(`${isoDate}T00:00:00`);
  if (Number.isNaN(d.getTime())) return null;
  const t = new Date();
  let a = t.getFullYear() - d.getFullYear();
  const m = t.getMonth() - d.getMonth();
  if (m < 0 || (m === 0 && t.getDate() < d.getDate())) a -= 1;
  return a;
}

export function profileKeyFromAge(age) {
  const n = Number(age);
  if (!Number.isFinite(n)) return "adult";
  if (n >= 6 && n <= 12) return "child";
  if (n >= 13 && n <= 17) return "teen";
  return "adult";
}

export function getProfile(key) {
  return PROFILES[key] ?? PROFILES.adult;
}

let seed = 1_234_567_89;

export function resetSeed() {
  seed = 1_234_567_89;
}

export function seededRandom() {
  seed = (1_664_525 * seed + 1_013_904_223) % 4_294_967_296;
  return seed / 4_294_967_296;
}

export function pickSeeded(arr) {
  return arr[Math.floor(seededRandom() * arr.length)];
}

export function pickTargetRandom(arr) {
  const c = globalThis.crypto;
  if (c?.getRandomValues) {
    const u = new Uint32Array(1);
    c.getRandomValues(u);
    return arr[u[0] % arr.length];
  }
  return arr[Math.floor(Math.random() * arr.length)];
}

function clamp(x, a = 0, b = 100) {
  return Math.max(a, Math.min(b, x));
}
function safeDiv(n, d) {
  return !d ? 0 : n / d;
}
function mean(a) {
  return a.length ? a.reduce((s, v) => s + v, 0) / a.length : 0;
}
function median(a) {
  if (!a.length) return 0;
  const s = [...a].sort((x, y) => x - y);
  const m = Math.floor(s.length / 2);
  return s.length % 2 ? s[m] : (s[m - 1] + s[m]) / 2;
}
function stdev(a) {
  if (a.length < 2) return 0;
  const u = mean(a);
  return Math.sqrt(mean(a.map((v) => (v - u) ** 2)));
}

/** Go/No-Go benzeri deneme logundan skorlar (lateMs = geç yanıt eşiği) */
export function computeMetrics(logs, lateMs) {
  const targets = logs.filter((t) => t.isTarget);
  const nonT = logs.filter((t) => !t.isTarget);
  const hits = targets.filter((t) => t.responded && t.reactionTime <= lateMs);
  const omissions = targets.filter((t) => !t.responded);
  const late = targets.filter((t) => t.responded && t.reactionTime > lateMs);
  const falseAlarms = nonT.filter((t) => t.responded);
  const correctRej = nonT.filter((t) => !t.responded);
  const multi = logs.filter((t) => t.responseCount > 1);
  const rts = targets.filter((t) => t.responded).map((t) => t.reactionTime).filter((r) => r > 0);

  const omissionR = safeDiv(omissions.length, targets.length);
  const faR = safeDiv(falseAlarms.length, nonT.length);
  const lateR = safeDiv(late.length, targets.length);
  const multiR = safeDiv(multi.length, logs.length);
  const acc = safeDiv(hits.length + correctRej.length, logs.length) * 100;

  const rtMed = median(rts);
  const rtStd = stdev(rts);

  const attention = clamp(100 - omissionR * 55 - lateR * 25 - faR * 20);
  const impulse = clamp(100 - faR * 70 - multiR * 30);
  const speed = clamp(100 - Math.max(0, rtMed - 450) * 0.08 - lateR * 30);
  const consistency = clamp(100 - Math.max(0, rtStd - 120) * 0.18 - lateR * 15);
  const overall = clamp(attention * 0.35 + impulse * 0.25 + speed * 0.2 + consistency * 0.2);

  const flags = [];
  if (omissionR >= 0.25) flags.push("Sürdürülebilir dikkatte zorlanma");
  if (faR >= 0.2) flags.push("Dürtüsel yanıtlar");
  if (lateR >= 0.2) flags.push("Geç tepkiler");
  if (multiR >= 0.1) flags.push("Çoklu basma");

  return {
    totalTrials: logs.length,
    accuracy: Math.round(acc),
    avgReaction: Math.round(mean(rts)),
    medianReaction: Math.round(rtMed),
    rtStd: Math.round(rtStd),
    omissionRate: omissionR * 100,
    falseAlarmRate: faR * 100,
    lateRate: lateR * 100,
    multiPressRate: multiR * 100,
    attentionScore: attention,
    impulseScore: impulse,
    speedScore: speed,
    consistencyScore: consistency,
    overallScore: overall,
    flags
  };
}

export function scoreSeries(logs, lateMs) {
  const att = [];
  const imp = [];
  const spd = [];
  const con = [];
  for (let i = 0; i < logs.length; i++) {
    const m = computeMetrics(logs.slice(0, i + 1), lateMs);
    att.push(Math.round(m.attentionScore));
    imp.push(Math.round(m.impulseScore));
    spd.push(Math.round(m.speedScore));
    con.push(Math.round(m.consistencyScore));
  }
  return { att, imp, spd, con };
}

export function riskLabel(m) {
  if (m.overallScore < 60 || m.omissionRate >= 25 || m.falseAlarmRate >= 20) return "Yüksek";
  if (m.overallScore < 75 || m.lateRate >= 20 || m.flags.length >= 2) return "Orta";
  return "Düşük";
}

export function summaryText(m, profileLabel) {
  return [
    `Test ${m.totalTrials} deneme ile tamamlandı. Profil: ${profileLabel}.`,
    `Genel skor ${Math.round(m.overallScore)}/100. Dikkat ${Math.round(m.attentionScore)}, dürtü kontrol ${Math.round(m.impulseScore)}, hız ${Math.round(m.speedScore)}, tutarlılık ${Math.round(m.consistencyScore)}.`,
    `Doğruluk %${m.accuracy}, median tepki ${m.medianReaction} ms.`,
    m.flags.length ? `Öne çıkanlar: ${m.flags.join("; ")}.` : "Belirgin uyarı yok.",
    "Bu yazılım tanı koymaz; yalnızca ön değerlendirme içindir."
  ].join(" ");
}

export function getGifPosition(area, zone) {
  const row = { upper: 26, middle: 50, lower: 74 };
  return { left: area === "left" ? 18 : 82, top: row[zone] ?? 50 };
}

export function getShapeSvg(shape, color) {
  const c = color;
  const map = {
    circle: `<svg width="72" height="72" viewBox="0 0 72 72"><circle cx="36" cy="36" r="30" fill="${c}"/></svg>`,
    square: `<svg width="72" height="72" viewBox="0 0 72 72"><rect x="10" y="10" width="52" height="52" fill="${c}"/></svg>`,
    triangle: `<svg width="72" height="72" viewBox="0 0 72 72"><polygon points="36,6 8,66 64,66" fill="${c}"/></svg>`,
    diamond: `<svg width="72" height="72" viewBox="0 0 72 72"><polygon points="36,4 68,36 36,68 4,36" fill="${c}"/></svg>`,
    pentagon: `<svg width="72" height="72" viewBox="0 0 72 72"><polygon points="36,5 66,28 54,66 18,66 6,28" fill="${c}"/></svg>`,
    hexagon: `<svg width="72" height="72" viewBox="0 0 72 72"><polygon points="20,8 52,8 66,36 52,64 20,64 6,36" fill="${c}"/></svg>`,
    vertical: `<svg width="72" height="72" viewBox="0 0 72 72"><rect x="28" y="6" width="16" height="60" fill="${c}"/></svg>`,
    horizontal: `<svg width="72" height="72" viewBox="0 0 72 72"><rect x="6" y="28" width="60" height="16" fill="${c}"/></svg>`,
    plus: `<svg width="72" height="72" viewBox="0 0 72 72"><rect x="28" y="8" width="16" height="56" fill="${c}"/><rect x="8" y="28" width="56" height="16" fill="${c}"/></svg>`,
    xshape: `<svg width="72" height="72" viewBox="0 0 72 72"><line x1="12" y1="12" x2="60" y2="60" stroke="${c}" stroke-width="12"/><line x1="60" y1="12" x2="12" y2="60" stroke="${c}" stroke-width="12"/></svg>`
  };
  return map[shape] ?? map.circle;
}

export function ShapeView({ shape, color, size = 100 }) {
  const b = { width: size, height: size, background: color, display: "inline-block" };
  if (shape === "circle") return <div style={{ ...b, borderRadius: "50%" }} />;
  if (shape === "square") return <div style={b} />;
  if (shape === "triangle") return <div style={{ ...b, clipPath: "polygon(50% 0%,0% 100%,100% 100%)" }} />;
  if (shape === "diamond") return <div style={{ ...b, transform: "rotate(45deg)" }} />;
  if (shape === "pentagon") {
    return <div style={{ ...b, clipPath: "polygon(50% 0%,100% 38%,82% 100%,18% 100%,0% 38%)" }} />;
  }
  if (shape === "hexagon") {
    return <div style={{ ...b, clipPath: "polygon(25% 0%,75% 0%,100% 50%,75% 100%,25% 100%,0% 50%)" }} />;
  }
  if (shape === "vertical") return <div style={{ width: size * 0.4, height: size, background: color, display: "inline-block" }} />;
  if (shape === "horizontal") return <div style={{ width: size, height: size * 0.4, background: color, display: "inline-block" }} />;
  if (shape === "plus") {
    return (
      <div style={{ width: size, height: size, position: "relative", display: "inline-block" }}>
        <div style={{ position: "absolute", left: size * 0.38, top: 0, width: size * 0.24, height: size, background: color }} />
        <div style={{ position: "absolute", left: 0, top: size * 0.38, width: size, height: size * 0.24, background: color }} />
      </div>
    );
  }
  if (shape === "xshape") {
    return (
      <div style={{ width: size, height: size, position: "relative", display: "inline-block" }}>
        <div style={{ position: "absolute", left: size * 0.42, top: 0, width: size * 0.16, height: size, background: color, transform: "rotate(45deg)" }} />
        <div style={{ position: "absolute", left: size * 0.42, top: 0, width: size * 0.16, height: size, background: color, transform: "rotate(-45deg)" }} />
      </div>
    );
  }
  return null;
}

import { useCallback, useEffect, useRef, useState } from "react";
import { COLORS, GIF_FILES, INDEPENDENT_SOUNDS, SHAPES } from "./constants.js";
import { getGifPosition } from "./shapeUtils.jsx";
import { pickSeeded, pickTargetRandom, resetSeed, seededRandom } from "./random.js";

export function useAttentionTest(profile, { onFinished } = {}) {
  const [target, setTarget] = useState(null);
  const [scene, setScene] = useState(null);
  const [gifs, setGifs] = useState([]);
  const [running, setRunning] = useState(false);

  const targetRef = useRef(null);
  const logRef = useRef([]);
  const trialRef = useRef(null);
  const timerRef = useRef(null);
  const clockRef = useRef(null);
  const eventTimers = useRef([]);
  const lastKey = useRef(0);
  const audioMap = useRef({});
  const playing = useRef(false);
  const t0 = useRef(0);
  const gifIds = useRef([]);
  const soundGifIds = useRef([]);
  const soloSoundId = useRef(null);

  const nextTrialRef = useRef(null);

  const mkTarget = useCallback(() => {
    const prev = targetRef.current;
    let next;
    let g = 0;
    do {
      next = { shape: pickTargetRandom(SHAPES), color: pickTargetRandom(COLORS) };
      g++;
    } while (prev && next.shape === prev.shape && next.color === prev.color && g < 40);
    targetRef.current = next;
    setTarget(next);
  }, []);

  const elapsed = useCallback(() => (t0.current ? performance.now() - t0.current : 0), []);

  const phaseNow = useCallback(
    (ms = elapsed()) => profile.phases.find((p) => ms < p.end) ?? profile.phases.at(-1),
    [profile.phases, elapsed]
  );

  const clearEvents = useCallback(() => {
    eventTimers.current.forEach(clearTimeout);
    eventTimers.current = [];
  }, []);

  const stopAudio = useCallback(() => {
    Object.values(audioMap.current).forEach((a) => {
      if (a) {
        a.pause();
        a.currentTime = 0;
        a.src = "";
      }
    });
    audioMap.current = {};
    soloSoundId.current = null;
    soundGifIds.current = [];
  }, []);

  const stopAll = useCallback(() => {
    clearEvents();
    stopAudio();
    gifIds.current = [];
    soundGifIds.current = [];
    setGifs([]);
  }, [clearEvents, stopAudio]);

  const removeGif = useCallback(
    (id) => {
      const a = audioMap.current[id];
      if (a) {
        a.pause();
        delete audioMap.current[id];
      }
      gifIds.current = gifIds.current.filter((x) => x !== id);
      soundGifIds.current = soundGifIds.current.filter((x) => x !== id);
      setGifs((p) => p.filter((g) => g.id !== id));
    },
    []
  );

  const canAdd = useCallback((items) => {
    const nS = items.filter((i) => !i.silent).length;
    if (!items.length) return false;
    if (gifIds.current.length + items.length > 2) return false;
    if (soundGifIds.current.length + nS > 1) return false;
    if (nS > 1) return false;
    return true;
  }, []);

  const showGif = useCallback(
    (idx) => {
      const ev = profile.gifEvents[idx];
      if (!ev || !playing.current || !canAdd(ev.items)) return;
      const items = ev.items
        .map((raw, i) => {
          const f = GIF_FILES[raw.key];
          if (!f) return null;
          const pos = getGifPosition(raw.area, raw.zone);
          return {
            id: `g-${idx}-${i}-${Date.now()}`,
            gif: f.gif,
            sound: raw.silent ? null : f.sound,
            left: pos.left,
            top: pos.top,
            size: f.size
          };
        })
        .filter(Boolean);
      if (!items.length) return;
      gifIds.current = [...gifIds.current, ...items.map((x) => x.id)];
      soundGifIds.current = [...soundGifIds.current, ...items.filter((x) => x.sound).map((x) => x.id)];
      setGifs((p) => [...p, ...items]);
      items.forEach((it) => {
        if (it.sound) {
          const a = new Audio(it.sound);
          a.loop = true;
          a.volume = 0.65;
          audioMap.current[it.id] = a;
          a.play().catch(() => removeGif(it.id));
        }
        eventTimers.current.push(setTimeout(() => removeGif(it.id), ev.duration));
      });
    },
    [canAdd, profile.gifEvents, removeGif]
  );

  const playSolo = useCallback(
    (idx) => {
      const ev = profile.soundEvents[idx];
      if (!ev || !playing.current || soloSoundId.current) return;
      const path = INDEPENDENT_SOUNDS[ev.key];
      if (!path) return;
      const id = `s-${idx}-${Date.now()}`;
      const a = new Audio(path);
      a.volume = 0.65;
      audioMap.current[id] = a;
      soloSoundId.current = id;
      a.play().catch(() => {
        delete audioMap.current[id];
        soloSoundId.current = null;
      });
      eventTimers.current.push(
        setTimeout(() => {
          a.pause();
          delete audioMap.current[id];
          if (soloSoundId.current === id) soloSoundId.current = null;
        }, ev.duration)
      );
    },
    [profile.soundEvents]
  );

  const scheduleDistractors = useCallback(() => {
    clearEvents();
    profile.gifEvents.forEach((e, i) => eventTimers.current.push(setTimeout(() => showGif(i), e.at)));
    profile.soundEvents.forEach((e, i) => eventTimers.current.push(setTimeout(() => playSolo(i), e.at)));
  }, [clearEvents, profile.gifEvents, profile.soundEvents, playSolo, showGif]);

  const flushTrial = useCallback(() => {
    const t = trialRef.current;
    if (t) {
      logRef.current.push({
        trialNumber: t.trialNumber,
        section: t.section,
        isTarget: t.isTarget,
        shownShape: t.shownShape,
        shownColor: t.shownColor,
        targetShape: t.targetShape,
        targetColor: t.targetColor,
        responded: t.responded,
        reactionTime: t.reactionTime || 0,
        responseCount: t.responses.length
      });
    }
    trialRef.current = null;
  }, []);

  const endTest = useCallback(() => {
    clearTimeout(timerRef.current);
    clearTimeout(clockRef.current);
    flushTrial();
    setScene(null);
    playing.current = false;
    setRunning(false);
    stopAll();
    onFinished?.();
  }, [flushTrial, onFinished, stopAll]);

  const nonTarget = useCallback(() => {
    const cur = targetRef.current;
    let o;
    do {
      o = { shape: pickSeeded(SHAPES), color: pickSeeded(COLORS) };
    } while (o.shape === cur.shape && o.color === cur.color);
    return o;
  }, []);

  const nextTrial = useCallback(() => {
    if (!playing.current) return;
    const ms = elapsed();
    if (ms >= profile.durationMs) {
      endTest();
      return;
    }
    const ph = phaseNow(ms);
    const n = logRef.current.length + 1;
    const isT = seededRandom() < profile.targetProbability;
    const cur = targetRef.current;
    const shown = isT ? { ...cur } : nonTarget();
    trialRef.current = {
      trialNumber: n,
      section: ph.name,
      isTarget: isT,
      shownShape: shown.shape,
      shownColor: shown.color,
      targetShape: cur.shape,
      targetColor: cur.color,
      responded: false,
      reactionTime: 0,
      responses: [],
      startTime: performance.now()
    };
    setScene({ shape: shown.shape, color: shown.color });
    timerRef.current = setTimeout(() => {
      setScene(null);
      const t = trialRef.current;
      if (t) {
        logRef.current.push({
          trialNumber: t.trialNumber,
          section: t.section,
          isTarget: t.isTarget,
          shownShape: t.shownShape,
          shownColor: t.shownColor,
          targetShape: t.targetShape,
          targetColor: t.targetColor,
          responded: t.responded,
          reactionTime: t.reactionTime || 0,
          responseCount: t.responses.length
        });
      }
      trialRef.current = null;
      timerRef.current = setTimeout(nextTrialRef.current, phaseNow().gap);
    }, ph.stimulus);
  }, [elapsed, endTest, nonTarget, phaseNow, profile.durationMs, profile.targetProbability]);

  nextTrialRef.current = nextTrial;

  const respond = useCallback(() => {
    const t = trialRef.current;
    if (!t) return;
    const now = performance.now();
    t.responses.push(now);
    if (!t.responded) {
      t.responded = true;
      t.reactionTime = now - t.startTime;
    }
  }, []);

  const register = useCallback(() => {
    const now = performance.now();
    if (now - lastKey.current < 120) return;
    lastKey.current = now;
    respond();
  }, [respond]);

  const start = useCallback(() => {
    resetSeed();
    logRef.current = [];
    trialRef.current = null;
    lastKey.current = 0;
    clearTimeout(timerRef.current);
    clearTimeout(clockRef.current);
    stopAll();
    setScene(null);
    t0.current = performance.now();
    playing.current = true;
    setRunning(true);
    scheduleDistractors();
    clockRef.current = setTimeout(endTest, profile.durationMs);
  }, [endTest, profile.durationMs, scheduleDistractors, stopAll]);

  const resetAfterReport = useCallback(() => {
    clearTimeout(timerRef.current);
    clearTimeout(clockRef.current);
    playing.current = false;
    stopAll();
    logRef.current = [];
    trialRef.current = null;
    t0.current = 0;
    setScene(null);
    resetSeed();
    mkTarget();
  }, [mkTarget, stopAll]);

  useEffect(() => {
    mkTarget();
    return () => {
      clearTimeout(timerRef.current);
      clearTimeout(clockRef.current);
      stopAll();
    };
  }, [profile.key, mkTarget, stopAll]);

  useEffect(() => {
    if (!running || !targetRef.current) return undefined;
    nextTrialRef.current();
    return () => clearTimeout(timerRef.current);
  }, [running]);

  useEffect(() => {
    const kd = (e) => {
      const el = document.activeElement;
      const typing =
        el && (el.tagName === "INPUT" || el.tagName === "TEXTAREA" || el.tagName === "SELECT" || el.isContentEditable);
      if (e.code === "Space" && !typing && playing.current) {
        e.preventDefault();
        register();
      }
    };
    window.addEventListener("keydown", kd);
    return () => window.removeEventListener("keydown", kd);
  }, [register]);

  const getLogs = useCallback(() => logRef.current.slice(), []);

  return { target, scene, gifs, running, start, register, resetAfterReport, getLogs };
}

import pdfMake from "pdfmake/build/pdfmake";
import pdfFonts from "pdfmake/build/vfs_fonts";
import { computeMetrics, riskLabel, summaryText } from "./metrics.js";
import { getShapeSvg } from "./shapeUtils.jsx";

pdfMake.vfs = pdfFonts.pdfMake ? pdfFonts.pdfMake.vfs : pdfFonts.vfs;

function color(score) {
  if (score >= 85) return "#16A34A";
  if (score >= 70) return "#65A30D";
  if (score >= 55) return "#F59E0B";
  return "#DC2626";
}

export function downloadPdf({ participant, profile, logs, target, chartImage }) {
  const m = computeMetrics(logs, profile.lateResponseMs);
  const risk = riskLabel(m);
  const text = summaryText(m, profile.label);
  const a = Math.round(m.attentionScore);
  const i = Math.round(m.impulseScore);
  const s = Math.round(m.speedScore);
  const c = Math.round(m.consistencyScore);
  const o = Math.round(m.overallScore);

  const doc = {
    pageSize: "A4",
    pageMargins: [40, 40, 40, 40],
    defaultStyle: { font: "Roboto", fontSize: 10 },
    content: [
      { text: "FocusProLab — Ön Değerlendirme Raporu", fontSize: 18, bold: true, color: "#0f172a", margin: [0, 0, 0, 8] },
      {
        columns: [
          {
            stack: [
              { text: `Katılımcı: ${participant.name}` },
              { text: `Yaş: ${participant.age}`, margin: [0, 4, 0, 0] },
              { text: `Profil: ${profile.label}`, margin: [0, 4, 0, 0] },
              { text: `Tarih: ${new Date().toLocaleString("tr-TR")}`, margin: [0, 4, 0, 0] },
              { text: `Risk (özet): ${risk}`, bold: true, margin: [0, 8, 0, 0] }
            ]
          },
          {
            width: 90,
            stack: [{ text: "Hedef", bold: true, alignment: "center" }, { svg: getShapeSvg(target.shape, target.color), width: 40, alignment: "center" }]
          }
        ],
        margin: [0, 0, 0, 16]
      },
      {
        columns: [
          { width: "*", text: `Genel\n${o}`, alignment: "center", fillColor: color(o), color: "#fff", margin: [4, 10, 4, 10] },
          { width: "*", text: `Dikkat\n${a}`, alignment: "center", fillColor: color(a), color: "#fff", margin: [4, 10, 4, 10] },
          { width: "*", text: `Dürtü\n${i}`, alignment: "center", fillColor: color(i), color: "#fff", margin: [4, 10, 4, 10] },
          { width: "*", text: `Hız\n${s}`, alignment: "center", fillColor: color(s), color: "#fff", margin: [4, 10, 4, 10] },
          { width: "*", text: `Tutarlılık\n${c}`, alignment: "center", fillColor: color(c), color: "#fff", margin: [4, 10, 4, 10] }
        ],
        columnGap: 4,
        margin: [0, 0, 0, 16]
      },
      {
        table: {
          widths: ["*", "auto"],
          body: [
            [{ text: "Ölçüm", bold: true }, { text: "Değer", bold: true }],
            ["Doğruluk %", String(m.accuracy)],
            ["Median RT (ms)", String(m.medianReaction)],
            ["Omission %", m.omissionRate.toFixed(1)],
            ["False alarm %", m.falseAlarmRate.toFixed(1)],
            ["Geç yanıt %", m.lateRate.toFixed(1)],
            ["Deneme sayısı", String(m.totalTrials)]
          ]
        },
        layout: {
          fillColor: (i) => (i === 0 ? "#334155" : i % 2 === 0 ? "#f8fafc" : null),
          hLineColor: () => "#e2e8f0",
          vLineColor: () => "#e2e8f0"
        },
        margin: [0, 0, 0, 16]
      },
      chartImage
        ? { text: "Performans grafiği", bold: true, margin: [0, 0, 0, 6] }
        : null,
      chartImage ? { image: chartImage, width: 500, margin: [0, 0, 0, 12] } : null,
      { text: "Metin özeti", bold: true, margin: [0, 8, 0, 6] },
      { text, alignment: "justify", lineHeight: 1.35 },
      {
        text: "Uyarı: Tanı koymaz; yalnızca ön değerlendirme amaçlıdır.",
        fontSize: 8,
        color: "#64748b",
        margin: [0, 20, 0, 0]
      }
    ].filter(Boolean)
  };

  pdfMake.createPdf(doc).download(`FocusProLab_${participant.name.replace(/\s+/g, "_")}_${Date.now()}.pdf`);
}

import { useCallback, useRef, useState } from "react";
import { Line } from "react-chartjs-2";
import { ageFromBirthDate, getProfile, profileKeyFromAge } from "./profiles.js";
import { computeMetrics, scoreSeries, summaryText } from "./metrics.js";
import { ShapeView } from "./shapeUtils.jsx";
import { useAttentionTest } from "./useAttentionTest.js";
import { downloadPdf } from "./pdfReport.js";

const input = {
  width: "100%",
  padding: "12px 14px",
  borderRadius: 12,
  border: "1px solid #cbd5e1",
  fontSize: 15,
  marginTop: 6
};

const card = {
  width: "100%",
  maxWidth: 640,
  background: "#fff",
  borderRadius: 20,
  padding: 28,
  boxShadow: "0 12px 40px rgba(15,23,42,0.1)"
};

export default function App() {
  const [step, setStep] = useState("form");
  const [name, setName] = useState("");
  const [birth, setBirth] = useState("");
  const [gender, setGender] = useState("");
  const [consent, setConsent] = useState(false);
  const [err, setErr] = useState("");
  const [age, setAge] = useState("");
  const [pkey, setPkey] = useState("adult");
  const [logs, setLogs] = useState([]);

  const chartRef = useRef(null);

  const profile = getProfile(pkey);

  const onDone = useCallback(() => {
    setStep("report");
  }, []);

  const { target, scene, gifs, running, start, register, resetAfterReport, getLogs } = useAttentionTest(profile, {
    onFinished: onDone
  });

  const participant = { name, age, birthDate: birth, gender };

  function submitForm(e) {
    e.preventDefault();
    setErr("");
    if (!name.trim()) {
      setErr("Ad soyad girin.");
      return;
    }
    const a = ageFromBirthDate(birth);
    if (a === null || a < 6 || a > 99) {
      setErr("Geçerli doğum tarihi (6–99 yaş).");
      return;
    }
    if (!gender) {
      setErr("Cinsiyet seçin.");
      return;
    }
    const k = profileKeyFromAge(a);
    if ((k === "child" || k === "teen") && !consent) {
      setErr("Çocuk/ergen için onam kutusunu işaretleyin.");
      return;
    }
    setAge(String(a));
    setPkey(k);
    setStep("brief");
  }

  function beginTest() {
    setLogs([]);
    start();
    setStep("run");
  }

  function openReport() {
    setLogs(getLogs());
    setStep("report");
  }

  const metrics = logs.length ? computeMetrics(logs, profile.lateResponseMs) : null;
  const series = logs.length ? scoreSeries(logs, profile.lateResponseMs) : null;

  const chartData = series
    ? {
        labels: logs.map((t) => t.trialNumber),
        datasets: [
          { label: "Dikkat", data: series.att, borderColor: "#2563eb", tension: 0.2, pointRadius: 0 },
          { label: "Dürtü", data: series.imp, borderColor: "#dc2626", tension: 0.2, pointRadius: 0 },
          { label: "Hız", data: series.spd, borderColor: "#16a34a", tension: 0.2, pointRadius: 0 },
          { label: "Tutarlılık", data: series.con, borderColor: "#d97706", tension: 0.2, pointRadius: 0 }
        ]
      }
    : null;

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", padding: "24px 16px 48px" }}>
      <header style={{ textAlign: "center", marginBottom: 20 }}>
        <h1 style={{ margin: 0, color: "#0f172a", fontSize: "1.75rem" }}>FocusProLab</h1>
        <p style={{ margin: "8px 0 0", color: "#475569", maxWidth: 520 }}>
          Hedef şekil ve renk birlikte gelince SPACE veya ekrana dokun. Yaşa göre süre ve fazlar değişir.
        </p>
      </header>

      {step === "form" && (
        <form onSubmit={submitForm} style={card}>
          <h2 style={{ marginTop: 0 }}>Katılımcı</h2>
          <label style={{ fontWeight: 600 }}>Ad soyad</label>
          <input value={name} onChange={(e) => setName(e.target.value)} style={input} autoComplete="name" />
          <label style={{ fontWeight: 600, display: "block", marginTop: 12 }}>Doğum tarihi</label>
          <input
            type="date"
            value={birth}
            onChange={(e) => {
              setBirth(e.target.value);
              const a = ageFromBirthDate(e.target.value);
              setPkey(a == null ? "adult" : profileKeyFromAge(a));
              if (profileKeyFromAge(a) === "adult") setConsent(false);
            }}
            style={input}
          />
          <label style={{ fontWeight: 600, display: "block", marginTop: 12 }}>Cinsiyet</label>
          <select value={gender} onChange={(e) => setGender(e.target.value)} style={input}>
            <option value="">Seçin</option>
            <option value="Kadın">Kadın</option>
            <option value="Erkek">Erkek</option>
          </select>
          {(pkey === "child" || pkey === "teen") && (
            <label style={{ display: "flex", gap: 10, marginTop: 14, alignItems: "flex-start", color: "#334155" }}>
              <input type="checkbox" checked={consent} onChange={(e) => setConsent(e.target.checked)} style={{ marginTop: 4 }} />
              <span>Veli / yasal temsilci bilgilendirme ve onamı alındı.</span>
            </label>
          )}
          {err && <p style={{ color: "#b91c1c", background: "#fef2f2", padding: 12, borderRadius: 12 }}>{err}</p>}
          <button
            type="submit"
            style={{
              marginTop: 20,
              width: "100%",
              padding: "14px 20px",
              border: "none",
              borderRadius: 14,
              background: "#142440",
              color: "#fff",
              fontWeight: 700,
              fontSize: 16,
              cursor: "pointer"
            }}
          >
            Devam
          </button>
        </form>
      )}

      {step === "brief" && target && (
        <div style={{ ...card, maxWidth: 720, textAlign: "center" }}>
          <h2>Test hazır</h2>
          <p style={{ color: "#475569" }}>
            Profil: <strong>{getProfile(pkey).label}</strong> — süre yaklaşık <strong>{Math.round(getProfile(pkey).durationMs / 60000)}</strong> dk.
          </p>
          <p>Aşağıdaki <strong>hedef</strong> göründüğünde yanıt ver.</p>
          <div
            style={{
              margin: "24px auto",
              width: 160,
              height: 160,
              borderRadius: 20,
              border: "3px solid #142440",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: "#f8fafc"
            }}
          >
            <ShapeView shape={target.shape} color={target.color} size={90} />
          </div>
          <button
            type="button"
            onClick={beginTest}
            style={{
              padding: "14px 28px",
              border: "none",
              borderRadius: 14,
              background: "#142440",
              color: "#fff",
              fontWeight: 700,
              fontSize: 16,
              cursor: "pointer"
            }}
          >
            Teste başla
          </button>
        </div>
      )}

      {step === "run" && running && (
        <div
          role="presentation"
          onClick={register}
          onTouchStart={register}
          style={{
            width: "min(96vw, 900px)",
            height: "min(72vh, 620px)",
            background: "#fff",
            borderRadius: 20,
            position: "relative",
            overflow: "hidden",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            cursor: "pointer",
            boxShadow: "0 12px 40px rgba(15,23,42,0.12)",
            touchAction: "manipulation",
            userSelect: "none"
          }}
        >
          {gifs.map((g) => (
            <img
              key={g.id}
              src={g.gif}
              alt=""
              onError={(e) => {
                e.target.style.display = "none";
              }}
              style={{
                position: "absolute",
                left: `${g.left}%`,
                top: `${g.top}%`,
                width: g.size,
                maxWidth: "32%",
                transform: "translate(-50%, -50%)",
                pointerEvents: "none",
                zIndex: 1
              }}
            />
          ))}
          {scene && (
            <div style={{ zIndex: 2 }}>
              <ShapeView shape={scene.shape} color={scene.color} size={140} />
            </div>
          )}
        </div>
      )}

      {step === "report" && target && metrics && (
        <div style={{ ...card, maxWidth: 900 }}>
          <h2 style={{ marginTop: 0 }}>Rapor</h2>
          <p style={{ color: "#475569" }}>
            {participant.name} — yaş {participant.age} — {profile.label}
          </p>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(120px, 1fr))", gap: 12, margin: "20px 0" }}>
            {[
              ["Genel", Math.round(metrics.overallScore)],
              ["Dikkat", Math.round(metrics.attentionScore)],
              ["Dürtü", Math.round(metrics.impulseScore)],
              ["Hız", Math.round(metrics.speedScore)],
              ["Tutarlılık", Math.round(metrics.consistencyScore)]
            ].map(([t, v]) => (
              <div key={t} style={{ background: "#142440", color: "#fff", padding: 14, borderRadius: 14, textAlign: "center" }}>
                <div style={{ fontSize: 13 }}>{t}</div>
                <div style={{ fontSize: 26, fontWeight: 800 }}>{v}</div>
              </div>
            ))}
          </div>
          <p style={{ lineHeight: 1.6, color: "#334155" }}>{summaryText(metrics, profile.label)}</p>
          {chartData && (
            <div style={{ height: 300, marginTop: 24 }}>
              <Line
                ref={chartRef}
                data={chartData}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  animation: false,
                  scales: { y: { min: 0, max: 100 } },
                  plugins: { legend: { position: "bottom" } }
                }}
              />
            </div>
          )}
          <div style={{ display: "flex", flexWrap: "wrap", gap: 12, marginTop: 24, justifyContent: "center" }}>
            <button
              type="button"
              onClick={() => {
                const url = chartRef.current?.canvas?.toDataURL("image/png", 0.92);
                downloadPdf({ participant, profile, logs, target, chartImage: url });
              }}
              style={{
                padding: "12px 22px",
                border: "none",
                borderRadius: 12,
                background: "#142440",
                color: "#fff",
                fontWeight: 700,
                cursor: "pointer"
              }}
