const box = { maxWidth: 400, margin: "0 auto", padding: 28, background: "#fff", borderRadius: 16, boxShadow: "0 8px 30px rgba(0,0,0,0.08)" };
const input = { width: "100%", padding: 12, borderRadius: 10, border: "1px solid #cbd5e1", marginTop: 6, fontSize: 15 };

export default function LoginPage() {
  const { user, isSupabaseReady } = useAuth();
  const [mode, setMode] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [msg, setMsg] = useState("");
  const [busy, setBusy] = useState(false);

  if (!isSupabaseReady) {
    return (
      <div style={{ padding: 24, maxWidth: 520, margin: "40px auto" }}>
        <h1>Yapılandırma gerekli</h1>
        <p>Supabase bağlantısı yok. Proje kökünde <code>.env</code> oluşturup <code>.env.example</code> içindeki değişkenleri doldurun, sunucuyu yeniden başlatın.</p>
      </div>
    );
  }

  if (user) return <Navigate to="/app" replace />;

  async function submit(e) {
    e.preventDefault();
    setMsg("");
    const em = email.trim().toLowerCase();
    if (!em || !password || password.length < 6) {
      setMsg("E-posta ve en az 6 karakter şifre gerekli.");
      return;
    }
    setBusy(true);
    try {
      if (mode === "login") {
        const { error } = await supabase.auth.signInWithPassword({ email: em, password });
        if (error) {
          setMsg(error.message);
          return;
        }
      } else {
        const { error } = await supabase.auth.signUp({ email: em, password });
        if (error) {
          setMsg(error.message);
          return;
        }
        setMsg("Kayıt alındı. E-posta doğrulaması açıksa gelen kutunu kontrol et, sonra giriş yap.");
        setMode("login");
      }
    } finally {
      setBusy(false);
    }
  }

  return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", padding: 24, background: "#f1f5f9" }}>
      <form onSubmit={submit} style={box}>
        <h1 style={{ marginTop: 0, textAlign: "center" }}>FocusProLab</h1>
        <p style={{ textAlign: "center", color: "#64748b" }}>{mode === "login" ? "Giriş" : "Hesap oluştur"}</p>
        <label style={{ fontWeight: 600 }}>E-posta</label>
        <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} style={input} autoComplete="email" />
        <label style={{ fontWeight: 600, display: "block", marginTop: 14 }}>Şifre</label>
        <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} style={input} autoComplete={mode === "login" ? "current-password" : "new-password"} />
        {msg && <p style={{ color: "#b91c1c", marginTop: 12 }}>{msg}</p>}
        <button
          type="submit"
          disabled={busy}
          style={{
            marginTop: 20,
            width: "100%",
            padding: 14,
            border: "none",
            borderRadius: 12,
            background: "#142440",
            color: "#fff",
            fontWeight: 700,
            cursor: busy ? "wait" : "pointer"
          }}
        >
          {busy ? "…" : mode === "login" ? "Giriş yap" : "Kayıt ol"}
        </button>
        <button type="button" onClick={() => { setMode(mode === "login" ? "register" : "login"); setMsg(""); }} style={{ marginTop: 12, width: "100%", border: "none", background: "none", color: "#142440", fontWeight: 600, cursor: "pointer" }}>
          {mode === "login" ? "Hesabım yok" : "Zaten hesabım var"}
        </button>
        <p style={{ marginTop: 20, textAlign: "center", fontSize: 14 }}>
          <Link to="/app">Panele dön</Link>
        </p>
      </form>
    </div>
  );
}

