  width: "100%",
  padding: "12px 14px",
  borderRadius: 12,
  border: "1px solid #cbd5e1",
  fontSize: 15,
  marginTop: 6
};

const card = {
  width: "100%",
  maxWidth: 640,
  background: "#fff",
  borderRadius: 20,
  padding: 28,
  boxShadow: "0 12px 40px rgba(15,23,42,0.1)"
};

export default function TestFlowPage() {
  const { user } = useAuth();
  const [step, setStep] = useState("form");
  const [name, setName] = useState("");
  const [birth, setBirth] = useState("");
  const [gender, setGender] = useState("");
  const [consent, setConsent] = useState(false);
  const [err, setErr] = useState("");
  const [age, setAge] = useState("");
  const [pkey, setPkey] = useState("adult");
  const [logs, setLogs] = useState([]);
  const [savedId, setSavedId] = useState(null);
  const [saveErr, setSaveErr] = useState("");
  const [saving, setSaving] = useState(false);

  const chartRef = useRef(null);
  const profile = getProfile(pkey);

  const onDone = useCallback(
    async (snapshot, targetSnap) => {
      setLogs(snapshot);
      setSaveErr("");
      if (!targetSnap || !user?.id) {
        setSaveErr("Hedef bilgisi veya oturum eksik; kayıt atlandı.");
        setStep("report");
        return;
      }
      const prof = getProfile(pkey);
      const m = computeMetrics(snapshot, prof.lateResponseMs);
      const sum = summaryText(m, prof.label);
      setSaving(true);
      try {
        const id = await saveTestSession({
          user_id: user.id,
          participant_name: name.trim(),
          participant_age: Number(age),
          participant_birth_date: birth || null,
          participant_gender: gender || null,
          consent_minor: consent,
          profile_key: pkey,
          target_shape: targetSnap.shape,
          target_color: targetSnap.color,
          trial_logs: snapshot,
          metrics: m,
          summary_text: sum,
          duration_ms: prof.durationMs
        });
        setSavedId(id);
      } catch (e) {
        setSaveErr(e.message ?? String(e));
      } finally {
        setSaving(false);
        setStep("report");
      }
    },
    [user, name, age, birth, gender, consent, pkey]
  );

  const { target, scene, gifs, running, start, register, resetAfterReport } = useAttentionTest(profile, {
    onFinished: onDone
  });

  const participant = { name, age, birthDate: birth, gender };

  function submitForm(e) {
    e.preventDefault();
    setErr("");
    if (!name.trim()) {
      setErr("Ad soyad girin.");
      return;
    }
    const a = ageFromBirthDate(birth);
    if (a === null || a < 6 || a > 99) {
      setErr("Geçerli doğum tarihi (6–99 yaş).");
      return;
    }
    if (!gender) {
      setErr("Cinsiyet seçin.");
      return;
    }
    const k = profileKeyFromAge(a);
    if ((k === "child" || k === "teen") && !consent) {
      setErr("Çocuk/ergen için onam kutusunu işaretleyin.");
      return;
    }
    setAge(String(a));
    setPkey(k);
    setStep("brief");
  }

  function beginTest() {
    setLogs([]);
    setSavedId(null);
    start();
    setStep("run");
  }

  async function persistPdf(blob) {
    if (!savedId || !user?.id) return;
    const path = await uploadReportPdf(user.id, savedId, blob);
    await updateSessionPdfPath(savedId, path);
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
      <header style={{ textAlign: "center", marginBottom: 20 }}>
        <h1 style={{ margin: 0, color: "#0f172a" }}>Dikkat testi</h1>
        <p style={{ margin: "8px 0 0", color: "#475569", maxWidth: 520 }}>
          Hedef şekil+renk birlikte gelince SPACE veya dokunma. Kayıtlar hesabına kaydedilir.
        </p>
      </header>

      {step === "form" && (
        <form onSubmit={submitForm} style={card}>
          <h2 style={{ marginTop: 0 }}>Katılımcı</h2>
          <label style={{ fontWeight: 600 }}>Ad soyad</label>
          <input value={name} onChange={(e) => setName(e.target.value)} style={input} autoComplete="name" />
          <label style={{ fontWeight: 600, display: "block", marginTop: 12 }}>Doğum tarihi</label>
          <input
            type="date"
            value={birth}
            onChange={(e) => {
              setBirth(e.target.value);
              const a = ageFromBirthDate(e.target.value);
              setPkey(a == null ? "adult" : profileKeyFromAge(a));
              if (profileKeyFromAge(a) === "adult") setConsent(false);
            }}
            style={input}
          />
          <label style={{ fontWeight: 600, display: "block", marginTop: 12 }}>Cinsiyet</label>
          <select value={gender} onChange={(e) => setGender(e.target.value)} style={input}>
            <option value="">Seçin</option>
            <option value="Kadın">Kadın</option>
            <option value="Erkek">Erkek</option>
          </select>
          {(pkey === "child" || pkey === "teen") && (
            <label style={{ display: "flex", gap: 10, marginTop: 14, alignItems: "flex-start", color: "#334155" }}>
              <input type="checkbox" checked={consent} onChange={(e) => setConsent(e.target.checked)} style={{ marginTop: 4 }} />
              <span>Veli / yasal temsilci bilgilendirme ve onamı alındı.</span>
            </label>
          )}
          {err && <p style={{ color: "#b91c1c", background: "#fef2f2", padding: 12, borderRadius: 12 }}>{err}</p>}
          <button
            type="submit"
            style={{
              marginTop: 20,
              width: "100%",
              padding: "14px 20px",
              border: "none",
              borderRadius: 14,
              background: "#142440",
              color: "#fff",
              fontWeight: 700,
              fontSize: 16,
              cursor: "pointer"
            }}
          >
            Devam
          </button>
        </form>
      )}

      {step === "brief" && target && (
        <div style={{ ...card, maxWidth: 720, textAlign: "center" }}>
          <h2>Test hazır</h2>
          <p style={{ color: "#475569" }}>
            Profil: <strong>{getProfile(pkey).label}</strong> — süre yaklaşık <strong>{Math.round(getProfile(pkey).durationMs / 60000)}</strong> dk.
          </p>
          <p>
            Aşağıdaki <strong>hedef</strong> göründüğünde yanıt ver.
          </p>
          <div
            style={{
              margin: "24px auto",
              width: 160,
              height: 160,
              borderRadius: 20,
              border: "3px solid #142440",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: "#f8fafc"
            }}
          >
            <ShapeView shape={target.shape} color={target.color} size={90} />
          </div>
          <button
            type="button"
            onClick={beginTest}
            style={{
              padding: "14px 28px",
              border: "none",
              borderRadius: 14,
              background: "#142440",
              color: "#fff",
              fontWeight: 700,
              fontSize: 16,
              cursor: "pointer"
            }}
          >
            Teste başla
          </button>
        </div>
      )}

      {step === "run" && running && (
        <div
          role="presentation"
          onClick={register}
          onTouchStart={register}
          style={{
            width: "min(96vw, 900px)",
            height: "min(72vh, 620px)",
            background: "#fff",
            borderRadius: 20,
            position: "relative",
            overflow: "hidden",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            cursor: "pointer",
            boxShadow: "0 12px 40px rgba(15,23,42,0.12)",
            touchAction: "manipulation",
            userSelect: "none"
          }}
        >
          {gifs.map((g) => (
            <img
              key={g.id}
              src={g.gif}
              alt=""
              onError={(e) => {
                e.target.style.display = "none";
              }}
              style={{
                position: "absolute",
                left: `${g.left}%`,
                top: `${g.top}%`,
                width: g.size,
                maxWidth: "32%",
                transform: "translate(-50%, -50%)",
                pointerEvents: "none",
                zIndex: 1
              }}
            />
          ))}
          {scene && (
            <div style={{ zIndex: 2 }}>
              <ShapeView shape={scene.shape} color={scene.color} size={140} />
            </div>
          )}
        </div>
      )}

      {step === "report" && target && logs.length > 0 && (
        <div style={{ ...card, maxWidth: 900 }}>
          {saving && <p>Kayıt yazılıyor…</p>}
          {saveErr && <p style={{ color: "#b91c1c" }}>{saveErr}</p>}
          <ReportPanel
            logs={logs}
            profile={profile}
            participant={participant}
            target={target}
            chartRef={chartRef}
            savedHint={savedId ? `Bu test kaydedildi (id: ${savedId.slice(0, 8)}…). PDF indirince dosya da buluta yüklenir.` : undefined}
            persistPdf={savedId ? persistPdf : undefined}
            extraActions={
              <>
                <button
                  type="button"
                  onClick={() => {
                    resetAfterReport();
                    setLogs([]);
                    setSavedId(null);
                    setSaveErr("");
                    setStep("brief");
                  }}
                  style={{ padding: "12px 22px", borderRadius: 12, border: "1px solid #cbd5e1", background: "#fff", cursor: "pointer" }}
                >
                  Aynı kişi — yeni test
                </button>
                <button
                  type="button"
                  onClick={() => {
                    resetAfterReport();
                    setName("");
                    setBirth("");
                    setGender("");
                    setConsent(false);
                    setAge("");
                    setPkey("adult");
                    setLogs([]);
                    setSavedId(null);
                    setErr("");
                    setSaveErr("");
                    setStep("form");
                  }}
                  style={{ padding: "12px 22px", borderRadius: 12, border: "1px solid #cbd5e1", background: "#f8fafc", cursor: "pointer" }}
                >
                  Yeni katılımcı
                </button>
                <Link to="/app" style={{ alignSelf: "center", padding: "12px 22px" }}>
                  Kayıtlara dön
                </Link>
              </>
            }
          />
        </div>
      )}
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { fetchSessionById } from "../services/sessions.js";
import { getProfile } from "../profiles.js";
import { ReportPanel } from "../components/ReportPanel.jsx";

export default function SessionDetailPage() {
  const { id } = useParams();
  const [row, setRow] = useState(null);
  const [err, setErr] = useState("");
  const chartRef = useRef(null);

  useEffect(() => {
    let ok = true;
    fetchSessionById(id)
      .then((d) => {
        if (ok) setRow(d);
      })
      .catch((e) => {
        if (ok) setErr(e.message ?? String(e));
      });
    return () => {
      ok = false;
    };
  }, [id]);

  if (err) return <p style={{ color: "#b91c1c" }}>{err}</p>;
  if (!row) return <p>Yükleniyor…</p>;

  const logs = Array.isArray(row.trial_logs) ? row.trial_logs : [];
  const profile = getProfile(row.profile_key);
  const target = { shape: row.target_shape, color: row.target_color };
  const participant = {
    name: row.participant_name,
    age: String(row.participant_age),
    birthDate: row.participant_birth_date,
    gender: row.participant_gender
  };

  return (
    <div>
      <p>
        <Link to="/app">← Kayıtlar</Link>
      </p>
      <ReportPanel
        logs={logs}
        profile={profile}
        participant={participant}
        target={target}
        chartRef={chartRef}
        savedHint={row.pdf_storage_path ? "PDF arşivlendi." : undefined}
      />
    </div>
  );
}

import { BrowserRouter, Navigate, Route, Routes } from "react-router-dom";
import { AuthProvider } from "./auth/AuthContext.jsx";
import AppLayout from "./pages/AppLayout.jsx";
import DashboardPage from "./pages/DashboardPage.jsx";
import LoginPage from "./pages/LoginPage.jsx";
import SessionDetailPage from "./pages/SessionDetailPage.jsx";
import TestFlowPage from "./pages/TestFlowPage.jsx";

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/app" element={<AppLayout />}>
            <Route index element={<DashboardPage />} />
            <Route path="test" element={<TestFlowPage />} />
            <Route path="kayit/:id" element={<SessionDetailPage />} />
          </Route>
          <Route path="/" element={<Navigate to="/app" replace />} />
          <Route path="*" element={<Navigate to="/app" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

