@keyframes space-probe-pulse {
  0%,
  100% {
    transform: translateY(0) scale(1);
    box-shadow: 0 5px 0 #0b1220, 0 12px 28px rgba(15, 23, 42, 0.28);
  }
  50% {
    transform: translateY(-2px) scale(1.03);
    box-shadow: 0 7px 0 #0b1220, 0 16px 36px rgba(20, 36, 64, 0.38);
  }
}

@keyframes space-probe-shine {
  0% {
    background-position: 0% 50%;
  }
  100% {
    background-position: 200% 50%;
  }
}

@keyframes space-probe-pop {
  0% {
    transform: scale(0.6);
    opacity: 0;
