/**
 * Degisiklikleri stage + commit + GitHub'a push.
 * Kullanim: npm run sync -- "mesaj"
 * Mesaj yoksa otomatik zaman damgasi kullanilir.
 */
import { execSync } from "node:child_process";

function run(cmd) {
  execSync(cmd, { stdio: "inherit", cwd: process.cwd(), shell: true });
}

const msg =
  process.argv.slice(2).join(" ").trim() ||
  `chore: sync ${new Date().toISOString().replace(/\.\d{3}Z$/, "Z")}`;

let porcelain;
try {
  porcelain = execSync("git status --porcelain", { encoding: "utf8" }).trim();
} catch {
  console.error("sync-github: git calismiyor veya repo degil.");
  process.exit(1);
}

if (!porcelain) {
  console.log("sync-github: commit edilecek degisiklik yok.");
  process.exit(0);
}

run("git add -A");
try {
  run(`git commit -m ${JSON.stringify(msg)}`);
} catch {
  console.error("sync-github: commit basarisiz.");
  process.exit(1);
}

try {
  run("git push origin HEAD");
} catch {
  console.error("sync-github: push basarisiz (ag / kimlik dogrulama). Commit yerelde.");
  process.exit(1);
}

console.log("sync-github: GitHub ile senkron.");

import { useCallback, useEffect, useRef, useState } from "react";
import { ageFromBirthDate, getProfile, profileKeyFromAge } from "./profiles.js";
import { ShapeView } from "./shapeUtils.jsx";
import { useAttentionTest } from "./useAttentionTest.js";
import { ReportPanel } from "./components/ReportPanel.jsx";

const input = {
  width: "100%",
  padding: "12px 14px",
  borderRadius: 12,
  border: "1px solid #cbd5e1",
  fontSize: 15,
  marginTop: 6
};

const card = {
  width: "100%",
  maxWidth: 640,
  background: "#fff",
  borderRadius: 20,
  padding: 28,
  boxShadow: "0 12px 40px rgba(15,23,42,0.1)"
};

export default function App() {
  const [step, setStep] = useState("form");
  const [name, setName] = useState("");
  const [birth, setBirth] = useState("");
  const [gender, setGender] = useState("");
  const [consent, setConsent] = useState(false);
  const [err, setErr] = useState("");
  const [age, setAge] = useState("");
  const [pkey, setPkey] = useState("adult");
  const [logs, setLogs] = useState([]);
  const [spaceVerified, setSpaceVerified] = useState(false);
  const [spaceCelebrating, setSpaceCelebrating] = useState(false);

  const spaceDoneLock = useRef(false);
  const chartRef = useRef(null);
  const profile = getProfile(pkey);

  const onDone = useCallback((snapshot) => {
    setLogs(snapshot);
    setStep("report");
  }, []);

  const { target, scene, gifs, running, start, register, resetAfterReport } = useAttentionTest(profile, {
    onFinished: onDone
  });

  const participant = { name, age, birthDate: birth, gender };

  const completeSpaceCheck = useCallback(() => {
    if (spaceCelebrating || spaceDoneLock.current) return;
    spaceDoneLock.current = true;
    setSpaceCelebrating(true);
    window.setTimeout(() => {
      setSpaceVerified(true);
      setStep("brief");
      setSpaceCelebrating(false);
      spaceDoneLock.current = false;
    }, 950);
  }, [spaceCelebrating]);

  function submitForm(e) {
    e.preventDefault();
    setErr("");
    if (!name.trim()) {
      setErr("Ad soyad girin.");
      return;
    }
    const a = ageFromBirthDate(birth);
    if (a === null || a < 6 || a > 99) {
      setErr("Geçerli doğum tarihi (6–99 yaş).");
      return;
    }
    if (!gender) {
      setErr("Cinsiyet seçin.");
      return;
    }
    const k = profileKeyFromAge(a);
    if ((k === "child" || k === "teen") && !consent) {
      setErr("Çocuk/ergen için onam kutusunu işaretleyin.");
      return;
    }
    setAge(String(a));
    setPkey(k);
    setSpaceVerified(false);
    spaceDoneLock.current = false;
    setSpaceCelebrating(false);
    setStep("spaceCheck");
  }

  function beginTest() {
    if (!spaceVerified) return;
    setLogs([]);
    start();
    setStep("run");
  }

  useEffect(() => {
    if (step !== "spaceCheck" || spaceCelebrating) return undefined;
    const kd = (e) => {
      if (e.code !== "Space") return;
      const el = document.activeElement;
      const typing =
        el && (el.tagName === "INPUT" || el.tagName === "TEXTAREA" || el.tagName === "SELECT" || el.isContentEditable);
      if (typing) return;
      e.preventDefault();
      completeSpaceCheck();
    };
    window.addEventListener("keydown", kd);
    return () => window.removeEventListener("keydown", kd);
  }, [step, spaceCelebrating, completeSpaceCheck]);

  useEffect(() => {
    if (step === "spaceCheck") {
      spaceDoneLock.current = false;
      setSpaceCelebrating(false);
    }
  }, [step]);

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", padding: "24px 16px 48px", background: "#f1f5f9" }}>
      {step !== "spaceCheck" && (
        <header style={{ textAlign: "center", marginBottom: 20 }}>
          <h1 style={{ margin: 0, color: "#0f172a" }}>FocusProLab</h1>
          <p style={{ margin: "8px 0 0", color: "#475569", maxWidth: 520 }}>
            Hedef şekil ve renk birlikte gelince SPACE veya ekrana dokun. Yaşa göre süre ve fazlar değişir.
          </p>
        </header>
      )}

      {step === "form" && (
        <form onSubmit={submitForm} style={card}>
          <h2 style={{ marginTop: 0 }}>Katılımcı</h2>
          <label style={{ fontWeight: 600 }}>Ad soyad</label>
          <input value={name} onChange={(e) => setName(e.target.value)} style={input} autoComplete="name" />
          <label style={{ fontWeight: 600, display: "block", marginTop: 12 }}>Doğum tarihi</label>
          <input
            type="date"
            value={birth}
            onChange={(e) => {
              setBirth(e.target.value);
              const a = ageFromBirthDate(e.target.value);
              setPkey(a == null ? "adult" : profileKeyFromAge(a));
              if (profileKeyFromAge(a) === "adult") setConsent(false);
            }}
            style={input}
          />
          <label style={{ fontWeight: 600, display: "block", marginTop: 12 }}>Cinsiyet</label>
          <select value={gender} onChange={(e) => setGender(e.target.value)} style={input}>
            <option value="">Seçin</option>
            <option value="Kadın">Kadın</option>
            <option value="Erkek">Erkek</option>
          </select>
          {(pkey === "child" || pkey === "teen") && (
            <label style={{ display: "flex", gap: 10, marginTop: 14, alignItems: "flex-start", color: "#334155" }}>
              <input type="checkbox" checked={consent} onChange={(e) => setConsent(e.target.checked)} style={{ marginTop: 4 }} />
              <span>Veli / yasal temsilci bilgilendirme ve onamı alındı.</span>
            </label>
          )}
          {err && <p style={{ color: "#b91c1c", background: "#fef2f2", padding: 12, borderRadius: 12 }}>{err}</p>}
          <button
            type="submit"
            style={{
              marginTop: 20,
              width: "100%",
              padding: "14px 20px",
              border: "none",
              borderRadius: 14,
              background: "#142440",
              color: "#fff",
              fontWeight: 700,
              fontSize: 16,
              cursor: "pointer"
            }}
          >
            Devam
          </button>
        </form>
      )}

      {step === "spaceCheck" && (
        <div className="space-screen">
          <div className="space-screen-bg" aria-hidden />
          <div className="space-screen-bg space-screen-bg--2" aria-hidden />
          <div className="space-screen-inner">
            <p className="space-screen-kicker">Adım 1 / 2 · Tuş kontrolü</p>
            {!spaceCelebrating ? (
              <>
                <h2 className="space-screen-head">Önce SPACE tuşunu deneyelim</h2>
                <p className="space-screen-sub">
                  Testte yanıt vereceğiniz tuş bu. Klavyede <strong>en uzun çubuk</strong> — boşluk (SPACE) tuşuna{" "}
                  <strong>şimdi bir kez</strong> basın.
                </p>
                <div className="space-screen-visual" aria-hidden="true">
                  <div className="space-screen-ring space-screen-ring--r1" />
                  <div className="space-screen-ring space-screen-ring--r2" />
                  <div className="space-screen-ring space-screen-ring--r3" />
                  <div className="space-screen-key-wrap">
                    <div className="space-screen-key space-screen-key--pulse">
                      <span className="space-screen-key-label">SPACE</span>
                    </div>
                  </div>
                </div>
                <p className="space-screen-nudge">Basın ↓</p>
                <button
                  type="button"
                  className="space-screen-touch"
                  onClick={() => completeSpaceCheck()}
                >
                  Klavye yok — dokunarak geç
                </button>
              </>
            ) : (
              <div className="space-screen-win" role="status" aria-live="polite">
                <div className="space-screen-win-burst" />
                <span className="space-screen-win-check">✓</span>
                <p className="space-screen-win-title">Süper!</p>
                <p className="space-screen-win-sub">Tuş algılandı — hazırlanıyorsunuz…</p>
              </div>
            )}
          </div>
        </div>
      )}

      {step === "brief" && target && (
        <div style={{ ...card, maxWidth: 720, textAlign: "center" }}>
          <p style={{ margin: "0 0 8px", fontSize: 13, color: "#64748b", fontWeight: 600 }}>Adım 2 / 2</p>
          <h2>Test hazır</h2>
          <p style={{ color: "#475569" }}>
            Profil: <strong>{getProfile(pkey).label}</strong> — süre yaklaşık <strong>{Math.round(getProfile(pkey).durationMs / 60000)}</strong> dk.
          </p>
          <p style={{ color: "#475569", marginTop: 8 }}>
            Test sırasında aşağıdaki <strong>hedef</strong> birlikte göründüğünde yanıt verin.
          </p>
          <div
            style={{
              margin: "24px auto",
              width: 160,
              height: 160,
              borderRadius: 20,
              border: "3px solid #142440",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: "#f8fafc"
            }}
          >
            <ShapeView shape={target.shape} color={target.color} size={90} />
          </div>
          <button
            type="button"
            onClick={beginTest}
            style={{
              padding: "14px 28px",
              border: "none",
              borderRadius: 14,
              background: "#142440",
              color: "#fff",
              fontWeight: 700,
              fontSize: 16,
              cursor: "pointer"
            }}
          >
            Teste başla
          </button>
        </div>
      )}

      {step === "run" && running && (
        <div
          role="presentation"
          onClick={register}
          onTouchStart={register}
          style={{
            width: "min(96vw, 900px)",
            height: "min(72vh, 620px)",
            background: "#fff",
            borderRadius: 20,
            position: "relative",
            overflow: "hidden",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            cursor: "pointer",
            boxShadow: "0 12px 40px rgba(15,23,42,0.12)",
            touchAction: "manipulation",
            userSelect: "none"
          }}
        >
          {gifs.map((g) => (
            <img
              key={g.id}
              src={g.gif}
              alt=""
              onError={(e) => {
                e.target.style.display = "none";
              }}
              style={{
                position: "absolute",
                left: `${g.left}%`,
                top: `${g.top}%`,
                width: g.size,
                maxWidth: "32%",
                transform: "translate(-50%, -50%)",
                pointerEvents: "none",
                zIndex: 1
              }}
            />
          ))}
          {scene && (
            <div style={{ zIndex: 2 }}>
              <ShapeView shape={scene.shape} color={scene.color} size={140} />
            </div>
          )}
        </div>
      )}

      {step === "report" && target && logs.length > 0 && (
        <div style={{ ...card, maxWidth: 900 }}>
          <ReportPanel
            logs={logs}
            profile={profile}
            participant={participant}
            target={target}
            chartRef={chartRef}
            extraActions={
              <>
                <button
                  type="button"
                  onClick={() => {
                    resetAfterReport();
                    setLogs([]);
                    setSpaceVerified(false);
                    spaceDoneLock.current = false;
                    setSpaceCelebrating(false);
                    setStep("spaceCheck");
                  }}
                  style={{ padding: "12px 22px", borderRadius: 12, border: "1px solid #cbd5e1", background: "#fff", cursor: "pointer" }}
                >
                  Aynı kişi — yeni test
                </button>
                <button
                  type="button"
                  onClick={() => {
                    resetAfterReport();
                    setName("");
                    setBirth("");
                    setGender("");
                    setConsent(false);
                    setAge("");
                    setPkey("adult");
                    setLogs([]);
                    setErr("");
                    setStep("form");
                  }}
                  style={{ padding: "12px 22px", borderRadius: 12, border: "1px solid #cbd5e1", background: "#f8fafc", cursor: "pointer" }}
                >
                  Yeni katılımcı
                </button>
              </>
            }
          />
        </div>
      )}
    </div>
  );
}

* {
  box-sizing: border-box;
}
body {
  margin: 0;
  font-family: system-ui, "Segoe UI", Arial, sans-serif;
  background: #f1f5f9;
}
#root {
  min-height: 100vh;
}

/* ——— Tam ekran SPACE kontrolü ——— */
.space-screen {
  position: relative;
  width: min(100%, 520px);
  min-height: min(78vh, 640px);
  margin: 0 auto;
  border-radius: 24px;
  overflow: hidden;
  box-shadow: 0 25px 60px rgba(15, 23, 42, 0.18);
}

.space-screen-bg {
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, #0f172a 0%, #1e3a5f 40%, #142440 70%, #0c1929 100%);
  background-size: 200% 200%;
  animation: space-screen-bg-move 12s ease infinite;
}

.space-screen-bg--2 {
  opacity: 0.35;
  background: radial-gradient(ellipse 80% 60% at 50% 30%, rgba(56, 189, 248, 0.35), transparent 55%),
    radial-gradient(ellipse 60% 50% at 80% 80%, rgba(129, 140, 248, 0.25), transparent 50%);
  animation: none;
}

@keyframes space-screen-bg-move {
  0%,
  100% {
    background-position: 0% 40%;
  }
  50% {
    background-position: 100% 60%;
  }
}

.space-screen-inner {
  position: relative;
  z-index: 2;
  padding: 32px 24px 36px;
  text-align: center;
  color: #e2e8f0;
  display: flex;
  flex-direction: column;
  align-items: center;
  min-height: min(78vh, 640px);
  justify-content: center;
}

.space-screen-kicker {
  margin: 0 0 16px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: #94a3b8;
}

.space-screen-head {
  margin: 0 0 12px;
  font-size: clamp(1.35rem, 4vw, 1.75rem);
  font-weight: 800;
  line-height: 1.25;
  background: linear-gradient(90deg, #f8fafc, #bae6fd, #f8fafc);
  background-size: 200% auto;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  animation: space-screen-shimmer 3s linear infinite;
}

@keyframes space-screen-shimmer {
  0% {
    background-position: 0% center;
  }
  100% {
    background-position: 200% center;
  }
}

.space-screen-sub {
  margin: 0 0 28px;
  font-size: 15px;
  line-height: 1.55;
  color: #cbd5e1;
  max-width: 400px;
}

.space-screen-visual {
  position: relative;
  width: 100%;
  max-width: 340px;
  height: 200px;
  margin: 0 auto 12px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.space-screen-ring {
  position: absolute;
  border-radius: 50%;
  border: 2px solid rgba(148, 163, 184, 0.35);
  pointer-events: none;
}

.space-screen-ring--r1 {
  width: 200px;
  height: 200px;
  animation: space-screen-spin 14s linear infinite;
}

.space-screen-ring--r2 {
  width: 164px;
  height: 164px;
  border-style: dashed;
  border-color: rgba(56, 189, 248, 0.45);
  animation: space-screen-spin 10s linear infinite reverse;
}

.space-screen-ring--r3 {
  width: 128px;
  height: 128px;
  border-color: rgba(244, 244, 245, 0.2);
  animation: space-screen-spin 7s linear infinite;
}

@keyframes space-screen-spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.space-screen-key-wrap {
  position: relative;
  z-index: 3;
}

.space-screen-key {
  position: relative;
  min-width: 220px;
  min-height: 58px;
  padding: 0 28px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(180deg, #475569 0%, #1e293b 45%, #0f172a 100%);
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow: 0 8px 0 #020617, 0 20px 40px rgba(0, 0, 0, 0.45);
  animation: space-screen-key-bounce 1.2s ease-in-out infinite;
  overflow: hidden;
}

.space-screen-key--pulse::after {
  content: "";
  position: absolute;
  inset: -40%;
  background: conic-gradient(from 180deg at 50% 50%, transparent 0deg, rgba(255, 255, 255, 0.09) 90deg, transparent 180deg);
  animation: space-screen-key-glow 3s linear infinite;
}

@keyframes space-screen-key-bounce {
  0%,
  100% {
    transform: translateY(0) scale(1);
  }
  45% {
    transform: translateY(-6px) scale(1.04);
  }
  55% {
    transform: translateY(-4px) scale(1.03);
  }
}

@keyframes space-screen-key-glow {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.space-screen-key-label {
  position: relative;
  z-index: 1;
  font-size: 17px;
  font-weight: 900;
  letter-spacing: 0.2em;
  color: #f8fafc;
  text-shadow: 0 2px 8px rgba(0, 0, 0, 0.5);
}

.space-screen-nudge {
  margin: 8px 0 20px;
  font-size: 14px;
  font-weight: 700;
  color: #fbbf24;
  animation: space-screen-nudge-pulse 1s ease-in-out infinite;
}

@keyframes space-screen-nudge-pulse {
  0%,
  100% {
    opacity: 0.85;
    transform: translateY(0);
  }
  50% {
    opacity: 1;
    transform: translateY(3px);
  }
}

.space-screen-touch {
  padding: 12px 20px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.25);
  background: rgba(15, 23, 42, 0.5);
  color: #e2e8f0;
  font-size: 14px;
  cursor: pointer;
  backdrop-filter: blur(6px);
}

.space-screen-touch:hover {
  background: rgba(30, 41, 59, 0.75);
}

.space-screen-win {
  position: relative;
  padding: 24px 20px 32px;
}

.space-screen-win-burst {
  position: absolute;
  inset: -20%;
  background: radial-gradient(circle, rgba(52, 211, 153, 0.35) 0%, transparent 65%);
  animation: space-screen-burst 0.8s ease-out forwards;
  pointer-events: none;
}

@keyframes space-screen-burst {
  from {
    opacity: 0;
    transform: scale(0.6);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

.space-screen-win-check {
  position: relative;
  display: inline-flex;
  width: 72px;
  height: 72px;
  align-items: center;
  justify-content: center;
  margin-bottom: 12px;
  border-radius: 50%;
  font-size: 38px;
  font-weight: 800;
  color: #065f46;
  background: linear-gradient(145deg, #d1fae5, #6ee7b7);
  box-shadow: 0 12px 30px rgba(16, 185, 129, 0.45);
  animation: space-screen-win-pop 0.55s cubic-bezier(0.34, 1.56, 0.64, 1);
}

@keyframes space-screen-win-pop {
  0% {
    transform: scale(0.3);
    opacity: 0;
  }
  100% {
    transform: scale(1);
    opacity: 1;
  }
}

.space-screen-win-title {
  position: relative;
  margin: 0 0 8px;
  font-size: 1.6rem;
  font-weight: 800;
  color: #ecfdf5;
}

.space-screen-win-sub {
  position: relative;
  margin: 0;
  font-size: 15px;
  color: #a7f3d0;
}

@media (prefers-reduced-motion: reduce) {
  .space-screen-bg,
  .space-screen-head,
  .space-screen-ring,
  .space-screen-key,
  .space-screen-key--pulse::after,
  .space-screen-nudge,
  .space-screen-win-burst,
  .space-screen-win-check {
    animation: none !important;
  }
  .space-screen-bg {
    background-position: 50% 50%;
  }
}

/** Çeldirici pencereleri: max 10 sn, aralar max 2 sn, sessiz gif max 2 ekranda */

const GIF_MS = 10_000;
const MAX_GAP_MS = 2_000;
const GIF_STEP_MS = GIF_MS - MAX_GAP_MS;

const GIF_KEYS = ["kedi", "top", "araba", "agac"];
const GIF_ZONES = [
  { area: "left", zone: "upper" },
  { area: "right", zone: "lower" },
  { area: "right", zone: "upper" },
  { area: "left", zone: "middle" }
];

const SOUND_KEYS = ["kussesi", "alarm", "tren", "insan"];
const SOUND_GIF_KEYS = ["top", "araba"];

function buildSilentGifWindow(startMs, endMs) {
  const events = [];
  let t = startMs;
  let i = 0;
  while (t < endMs) {
    const duration = Math.min(GIF_MS, endMs - t);
    if (duration < 800) break;
    const z = GIF_ZONES[i % GIF_ZONES.length];
    events.push({
      at: t,
      duration,
      items: [{ key: GIF_KEYS[i % GIF_KEYS.length], area: z.area, zone: z.zone, silent: true }]
    });
    t += GIF_STEP_MS;
    i += 1;
  }
  return events;
}

function buildSoloSoundWindow(startMs, endMs) {
  const events = [];
  let t = startMs;
  let i = 0;
  while (t < endMs) {
    const duration = Math.min(GIF_MS, endMs - t);
    if (duration < 800) break;
    events.push({ at: t, duration, key: SOUND_KEYS[i % SOUND_KEYS.length] });
    t += duration + MAX_GAP_MS;
    i += 1;
  }
  return events;
}

/** Sesli gif + aynı pencerede sessiz gifler */
function buildSoundGifWindow(startMs, endMs) {
  const silent = buildSilentGifWindow(startMs, endMs);
  const soundGifs = [];
  let t = startMs;
  let i = 0;
  while (t < endMs) {
    const duration = Math.min(GIF_MS, endMs - t);
    if (duration < 800) break;
    soundGifs.push({
      at: t,
      duration,
      items: [
        {
          key: SOUND_GIF_KEYS[i % SOUND_GIF_KEYS.length],
          area: i % 2 ? "right" : "left",
          zone: "lower",
          silent: false
        }
      ]
    });
    t += GIF_MS + MAX_GAP_MS;
    i += 1;
  }
  return [...silent, ...soundGifs].sort((a, b) => a.at - b.at);
}

export function mergeGifEvents(windows) {
  return windows.flat().sort((a, b) => a.at - b.at);
}

export function mergeSoundEvents(windows) {
  return windows.flat().sort((a, b) => a.at - b.at);
}

export { buildSilentGifWindow, buildSoloSoundWindow, buildSoundGifWindow };

/**
 * Test kıstasları (Çocuk 13 dk, Olgun/Yetişkin 15 dk, Ergen 16 dk).
 * Ana simge hızı = stimulus (ms). gap ≈ stimulus'un %45'i.
 */

import {
  buildSilentGifWindow,
  buildSoloSoundWindow,
  buildSoundGifWindow,
  mergeGifEvents,
  mergeSoundEvents
} from "./distractorSchedule.js";

const MIN = 60_000;

function phase(endMin, name, stimulus) {
  return {
    end: endMin * MIN,
    name,
    stimulus,
    gap: Math.round(stimulus * 0.45)
  };
}

/** Çocuk — 13 dk */
const childPhases = [
  phase(2, "Çocuk — 0–2 dk", 1800),
  phase(5, "Çocuk — 2–5 dk", 1700),
  phase(7, "Çocuk — 5–7 dk", 1600),
  phase(10, "Çocuk — 7–10 dk (sessiz gif)", 1600),
  phase(11, "Çocuk — 10–11 dk (sadece ses)", 1600),
  phase(12, "Çocuk — 11–12 dk (sesli gif)", 1600),
  phase(13, "Çocuk — 12–13 dk", 1850)
];

const childGif = mergeGifEvents([
  buildSilentGifWindow(7 * MIN, 10 * MIN),
  buildSoundGifWindow(11 * MIN, 12 * MIN)
]);

const childSound = mergeSoundEvents([buildSoloSoundWindow(10 * MIN, 11 * MIN)]);

/** Olgun / Yetişkin — 15 dk */
const adultPhases = [
  phase(2, "Yetişkin — 0–2 dk", 1400),
  phase(5, "Yetişkin — 2–5 dk", 1200),
  phase(7, "Yetişkin — 5–7 dk", 1100),
  phase(9, "Yetişkin — 7–9 dk (sessiz gif)", 1100),
  phase(10, "Yetişkin — 9–10 dk (sadece ses)", 1100),
  phase(11, "Yetişkin — 10–11 dk (sesli gif)", 900),
  phase(15, "Yetişkin — 11–15 dk", 1100)
];

const adultGif = mergeGifEvents([
  buildSilentGifWindow(7 * MIN, 9 * MIN),
  buildSoundGifWindow(10 * MIN, 11 * MIN)
]);

const adultSound = mergeSoundEvents([buildSoloSoundWindow(9 * MIN, 10 * MIN)]);

/** Ergen — 16 dk */
const teenPhases = [
  phase(3, "Ergen — 0–3 dk", 1300),
  phase(6, "Ergen — 3–6 dk", 1100),
  phase(7, "Ergen — 6–7 dk", 1000),
  phase(8, "Ergen — 7–8 dk", 900),
  phase(9, "Ergen — 8–9 dk", 800),
  phase(11, "Ergen — 9–11 dk (sessiz gif)", 1100),
  phase(12, "Ergen — 11–12 dk (sadece ses)", 900),
  phase(14, "Ergen — 12–14 dk (sesli gif)", 1200),
  phase(16, "Ergen — 14–16 dk", 1100)
];

const teenGif = mergeGifEvents([
  buildSilentGifWindow(9 * MIN, 11 * MIN),
  buildSoundGifWindow(12 * MIN, 14 * MIN)
]);

const teenSound = mergeSoundEvents([buildSoloSoundWindow(11 * MIN, 12 * MIN)]);

export const PROFILES = {
  child: {
    key: "child",
    label: "Çocuk (6–12)",
    durationMs: 13 * MIN,
    lateResponseMs: 1000,
    targetProbability: 0.45,
    phases: childPhases,
    gifEvents: childGif,
    soundEvents: childSound
  },
  teen: {
    key: "teen",
    label: "Ergen (13–17)",
    durationMs: 16 * MIN,
    lateResponseMs: 900,
    targetProbability: 0.42,
    phases: teenPhases,
    gifEvents: teenGif,
    soundEvents: teenSound
  },
  adult: {
    key: "adult",
    label: "Yetişkin (18+)",
    durationMs: 15 * MIN,
    lateResponseMs: 800,
    targetProbability: 0.4,
    phases: adultPhases,
    gifEvents: adultGif,
    soundEvents: adultSound
  }
};

export function ageFromBirthDate(isoDate) {
  if (!isoDate) return null;
  const d = new Date(`${isoDate}T00:00:00`);
  if (Number.isNaN(d.getTime())) return null;
  const t = new Date();
  let a = t.getFullYear() - d.getFullYear();
  const m = t.getMonth() - d.getMonth();
  if (m < 0 || (m === 0 && t.getDate() < d.getDate())) a -= 1;
  return a;
}

export function profileKeyFromAge(age) {
  const n = Number(age);
  if (!Number.isFinite(n)) return "adult";
  if (n >= 6 && n <= 12) return "child";
  if (n >= 13 && n <= 17) return "teen";
  return "adult";
}

export function getProfile(key) {
  return PROFILES[key] ?? PROFILES.adult;
}

